/* INTERNAL USE ONLY: Create handle from frame pointer using container_of */
static inline JSAsyncFunctionStateHandle async_func_from_frame(JSStackFrame* frame) {
    if (!frame) return JSAsyncFunctionStateHandle();
    JSAsyncFunctionState* state = container_of(frame, JSAsyncFunctionState, frame);
    return JSAsyncFunctionStateHandle(state->self_handle);
}

/* Ensure GC is initialized before any allocation */
static inline void gc_assert_initialized(void) {
    if (__builtin_expect(!g_gc.initialized, 0)) {
#ifdef BE_PLATFORM_ANDROID
        __android_log_print(ANDROID_LOG_ERROR, "QuickJS", 
            "FATAL: GC not initialized! Call gc_init() before any QuickJS operations.");
#endif
#ifdef _MSC_VER
        __debugbreak();  /* Hard crash in debug builds */
#else
        __builtin_trap();  /* Hard crash in debug builds */
#endif
    }
}
