/* Debug logging - controlled via QJS_DEBUG environment variable or compile flag
 * 
 * To enable debug logging at compile time:
 *   -DQJS_DEBUG_ENABLED=1
 * 
 * To enable debug logging at runtime (macOS/Linux):
 *   QJS_DEBUG=1 ./your_program
 * 
 * Set QJS_DEBUG to the desired log level:
 *   QJS_DEBUG=1  - Info level and above
 *   QJS_DEBUG=2  - Debug level and above (verbose)
 */
#ifdef BE_PLATFORM_ANDROID
#include <android/log.h>
#endif

/* Default: logging disabled. Override with -DQJS_DEBUG_ENABLED=1 at compile time */
#ifndef QJS_DEBUG_ENABLED
#define QJS_DEBUG_ENABLED 0
#endif

/* Runtime check for QJS_DEBUG environment variable */
#include <stdlib.h>
static inline int qjs_debug_level(void) {
    static int level = -1;
    if (level < 0) {
        const char *env = getenv("QJS_DEBUG");
        if (env) {
            level = atoi(env);
            if (level == 0 && env[0] != '0') level = 1;  /* QJS_DEBUG=1 if set to any non-numeric */
        } else {
            level = QJS_DEBUG_ENABLED ? 1 : 0;
        }
    }
    return level;
}

/* Logging macros that check runtime/debug level */
#if QJS_DEBUG_ENABLED
#define QJS_LOG_ENABLED 1
#else
#define QJS_LOG_ENABLED qjs_debug_level()
#endif

#ifdef BE_PLATFORM_ANDROID
#define QJS_LOGD(...) do { if (qjs_debug_level() >= 2) { __android_log_print(ANDROID_LOG_DEBUG, "quickjs", __VA_ARGS__); } } while(0)
#define QJS_LOGI(...) do { if (qjs_debug_level() >= 1) { __android_log_print(ANDROID_LOG_INFO, "quickjs", __VA_ARGS__); } } while(0)
#define QJS_LOGW(...) do { if (qjs_debug_level() >= 1) { __android_log_print(ANDROID_LOG_WARN, "quickjs", __VA_ARGS__); } } while(0)
#define QJS_LOGE(...) __android_log_print(ANDROID_LOG_ERROR, "quickjs", __VA_ARGS__)
#else
/* macOS/Linux: print to stderr */
#include <stdio.h>
#define QJS_LOGD(...) do { if (qjs_debug_level() >= 2) { fprintf(stderr, "[D/quickjs] " __VA_ARGS__); fprintf(stderr, "\n"); fflush(stderr); } } while(0)
#define QJS_LOGI(...) do { if (qjs_debug_level() >= 1) { fprintf(stderr, "[I/quickjs] " __VA_ARGS__); fprintf(stderr, "\n"); fflush(stderr); } } while(0)
#define QJS_LOGW(...) do { if (qjs_debug_level() >= 1) { fprintf(stderr, "[W/quickjs] " __VA_ARGS__); fprintf(stderr, "\n"); fflush(stderr); } } while(0)
#define QJS_LOGE(...) do { fprintf(stderr, "[E/quickjs] " __VA_ARGS__); fprintf(stderr, "\n"); fflush(stderr); } while(0)
#endif

/* File logging for debugging */
#ifndef _WIN32
#include <fcntl.h>
#include <unistd.h>
#endif
#include <stdarg.h>
#ifndef _WIN32
static void file_log_quickjs(const char *fmt, ...) {
    static int log_fd = -1;
    if (log_fd < 0) {
#ifdef __APPLE__
        /* macOS: use /tmp for debug log */
        log_fd = open("/tmp/qjs_debug.log", 
                      O_WRONLY | O_CREAT | O_TRUNC, 0644);
#else
        /* Android: use app-specific directory */
        log_fd = open("/data/data/com.bgmdwldr.vulkan/qjs_debug.log", 
                      O_WRONLY | O_CREAT | O_APPEND, 0644);
#endif
    }
    if (log_fd >= 0) {
        char buf[1024];
        va_list args;
        va_start(args, fmt);
        int n = vsnprintf(buf, sizeof(buf), fmt, args);
        va_end(args);
        if (n > 0 && n < sizeof(buf) - 1) {
            buf[n++] = '\n';
            write(log_fd, buf, n);
        }
    }
}
#endif

