/* Handle class for GCHandle arrays - provides safe indexed access */
class GCHandleArrayHandle {
private:
    GCHandle handle_;
    
    GCHandle* get_ptr() const {
        if (handle_ == GC_HANDLE_NULL) return nullptr;
        return (GCHandle*)gc_deref(handle_);
    }

public:
    GCHandleArrayHandle() : handle_(GC_HANDLE_NULL) {}
    explicit GCHandleArrayHandle(GCHandle handle) : handle_(handle) {}
    
    GCHandle handle() const { return handle_; }
    bool valid() const { return handle_ != GC_HANDLE_NULL; }
    explicit operator bool() const { return valid(); }
    
    /* Array access - returns handle at index */
    GCHandle operator[](int index) const {
        GCHandle* p = get_ptr();
        return p ? p[index] : GC_HANDLE_NULL;
    }
    
    /* Get raw pointer for iteration (use with caution) */
    GCHandle* ptr() const {
        return get_ptr();
    }
};

