static int init_class_range(JSRuntimeHandle rt, JSClassShortDef const *tab,
                            int start, int count)
{
    JSClassDef cm_s, *cm = &cm_s;
    int i, class_id;

    for(i = 0; i < count; i++) {
        class_id = i + start;
        memset(cm, 0, sizeof(*cm));
        cm->finalizer = tab[i].finalizer;
        cm->gc_mark = tab[i].gc_mark;
        if (JS_NewClass1(rt, class_id, cm, tab[i].class_name) < 0)
            return -1;
    }
    return 0;
}

#if !defined(CONFIG_STACK_CHECK)
/* no stack limitation */
static inline uintptr_t js_get_stack_pointer(void)
{
    return 0;
}

static inline BOOL js_check_stack_overflow(JSRuntimeHandle rt, size_t alloca_size)
{
    return FALSE;
}
#else
/* Note: OS and CPU dependent */
static inline uintptr_t js_get_stack_pointer(void)
{
#ifdef _MSC_VER
    return (uintptr_t)_AddressOfReturnAddress();
#else
    return (uintptr_t)__builtin_frame_address(0);
#endif
}

static inline BOOL js_check_stack_overflow(JSRuntimeHandle rt, size_t alloca_size)
{
    uintptr_t sp;
    sp = js_get_stack_pointer() - alloca_size;
    return unlikely(sp < rt.stack_limit());
}
#endif

/* Forward declarations for GC finalizers */
static void js_runtime_finalizer(JSRuntimeHandle rt, GCHandle handle, void *user_ptr);
static void js_context_finalizer(JSRuntimeHandle rt, GCHandle handle, void *user_ptr);

JSRuntimeHandle JS_NewRuntime(void)
{
    JSRuntimeHandle rt;
    JSMallocState ms;

    /* GC must be initialized BEFORE calling this function */
    gc_assert_initialized();
    

    memset(&ms, 0, sizeof(ms));
    ms.malloc_limit = (size_t)-1;  /* Use max size_t value */

    GCHandle rt_handle = gc_alloc(sizeof(JSRuntime), JS_GC_OBJ_TYPE_JS_RUNTIME);
    if (rt_handle == GC_HANDLE_NULL) {
        QJS_LOGE("JS_NewRuntime: Failed to allocate JSRuntime");
        return JSRuntimeHandle();
    }
    rt = JSRuntimeHandle(rt_handle);
    rt.zero_memory();
    
    /* Set finalizer to free malloc'd resources */
    gc_set_handle_finalizer(rt_handle, js_runtime_finalizer);
    
    /* Bug #2 fix: Set runtime pointer for GC tracking */
    gc_set_runtime(rt);
    
    gc_add_root(rt_handle);
    
    rt.set_malloc_state(ms);
    rt.set_malloc_gc_threshold(256 * 1024);

    QJS_LOGI("JS_NewRuntime: Starting initialization...");

    /* Typed handle arrays are initialized in gc_init() */
    
    rt.set_gc_phase(JS_GC_PHASE_NONE);

    QJS_LOGI("JS_NewRuntime: Calling JS_InitAtoms...");
    if (JS_InitAtoms(rt)) {
        QJS_LOGE("JS_NewRuntime: JS_InitAtoms failed");
        goto fail;
    }
    QJS_LOGI("JS_NewRuntime: JS_InitAtoms succeeded");

    /* create the object, array and function classes */
    QJS_LOGI("JS_NewRuntime: Calling init_class_range...");
    if (init_class_range(rt, js_std_class_def, JS_CLASS_OBJECT,
                         countof(js_std_class_def)) < 0) {
        QJS_LOGE("JS_NewRuntime: init_class_range failed");
        goto fail;
    }
    QJS_LOGI("JS_NewRuntime: init_class_range succeeded");
    
    ((JSClass*)rt_class_array)[JS_CLASS_ARGUMENTS].exotic = &js_arguments_exotic_methods;
    ((JSClass*)rt_class_array)[JS_CLASS_MAPPED_ARGUMENTS].exotic = &js_arguments_exotic_methods;
    ((JSClass*)rt_class_array)[JS_CLASS_STRING].exotic = &js_string_exotic_methods;
    ((JSClass*)rt_class_array)[JS_CLASS_MODULE_NS].exotic = &js_module_ns_exotic_methods;

    ((JSClass*)rt_class_array)[JS_CLASS_C_FUNCTION].call = js_call_c_function;
    ((JSClass*)rt_class_array)[JS_CLASS_C_FUNCTION_DATA].call = js_c_function_data_call;
    ((JSClass*)rt_class_array)[JS_CLASS_BOUND_FUNCTION].call = js_call_bound_function;
    ((JSClass*)rt_class_array)[JS_CLASS_GENERATOR_FUNCTION].call = js_generator_function_call;
    
    QJS_LOGI("JS_NewRuntime: Calling init_shape_hash...");
    if (init_shape_hash(rt)) {
        QJS_LOGE("JS_NewRuntime: init_shape_hash failed");
        goto fail;
    }
    QJS_LOGI("JS_NewRuntime: init_shape_hash succeeded");

    rt.set_stack_size(JS_DEFAULT_STACK_SIZE);
    JS_UpdateStackTop(rt);

    rt.set_current_exception(JS_UNINITIALIZED);

    QJS_LOGI("JS_NewRuntime: Initialization complete!");
    return rt;
 fail:
    QJS_LOGE("JS_NewRuntime: FAILED at initialization step (see above). Aborting.");
    /* Don't call JS_FreeRuntime on partial initialization - just crash */
    abort();
}

