#define GET_ARRAY_EL_INLINE(name, keep)                                 \
            {                                                           \
                GCValue val, obj, prop;                                 \
                JSObjectHandle p;                                            \
                uint32_t idx;                                           \
                                                                        \
                obj = sp[-2];                                           \
                prop = sp[-1];                                          \
