static void js_iterator_wrap_mark(JSRuntimeHandle rt, GCValue val,
                                  JS_MarkFunc *mark_func)
{
    JSObjectHandle p = JS_VALUE_GET_OBJ(val);
    JSIteratorWrapDataHandle it = p.iterator_wrap_data_handle();
    if (it.valid()) {
        /* The iterator-wrap data object is a separate GC allocation; keep it alive. */
        mark_func(rt, it.handle());
        JS_MarkValue(rt, it.wrapped_iter(), mark_func);
        JS_MarkValue(rt, it.wrapped_next(), mark_func);
    }
}

static GCValue js_iterator_wrap_next(JSContextHandle ctx, GCValue this_val,
                                     int argc, GCValue *argv,
                                     int *pdone, int magic)
{
    GCValue method, ret;
    GCHandle it_handle = JS_GetOpaqueHandle2(ctx, this_val, JS_CLASS_ITERATOR_WRAP);
    if (it_handle == GC_HANDLE_NULL)
        return JS_EXCEPTION;
    JSIteratorWrapDataHandle it(it_handle);
    if (magic == GEN_MAGIC_NEXT) {
        return JS_IteratorNext(ctx, it.wrapped_iter(), it.wrapped_next(), 0, NULL, pdone);
    } else {
        method = JS_GetProperty(ctx, it.wrapped_iter(), JS_ATOM_return);
        if (JS_IsException(method))
            return JS_EXCEPTION;
        if (JS_IsNull(method) || JS_IsUndefined(method)) {
            *pdone = TRUE;
            return JS_UNDEFINED;
        }
        ret = JS_IteratorNext2(ctx, it.wrapped_iter(), method, 0, NULL, pdone);
        
        return ret;
    }
}

