/* Iterator */

static GCValue js_iterator_constructor_getset(JSContextHandle ctx,
                                              GCValue this_val,
                                              int argc, GCValue *argv,
                                              int magic,
                                              GCValue *func_data)
{
    int ret;

    if (argc > 0) { // if setter
        if (!JS_IsObject(argv[0]))
            return JS_ThrowTypeErrorNotAnObject(ctx);
        ret = JS_DefinePropertyValue(ctx, this_val, JS_ATOM_constructor,
                                     argv[0],
                                     JS_PROP_WRITABLE | JS_PROP_CONFIGURABLE);
        if (ret < 0)
            return JS_EXCEPTION;
        return JS_UNDEFINED;
    } else {
        return func_data[0];
    }
}

static GCValue js_iterator_constructor(JSContextHandle ctx, GCValue new_target,
                                       int argc, GCValue *argv)
{
    JSObjectHandle p;

    if (JS_TAG_OBJECT != JS_VALUE_GET_TAG(new_target))
        return JS_ThrowTypeError(ctx, "constructor requires 'new'");
    p = JS_VALUE_GET_OBJ(new_target);
    if (p.class_id() == JS_CLASS_C_FUNCTION &&
        p.cfunc_c_function().generic == js_iterator_constructor) {
        return JS_ThrowTypeError(ctx, "abstract class not constructable");
    }
    return js_create_from_ctor(ctx, new_target, JS_CLASS_ITERATOR);
}

