static GCValue js_number_isInteger(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv)
{
    int ret;
    ret = JS_NumberIsInteger(ctx, argv[0]);
    if (ret < 0)
        return JS_EXCEPTION;
    else
        return JS_NewBool(ctx, ret);
}

static GCValue js_number_isSafeInteger(JSContextHandle ctx, GCValue this_val,
                                       int argc, GCValue *argv)
{
    double d;
    if (!JS_IsNumber(argv[0]))
        return JS_FALSE;
    if (unlikely(JS_ToFloat64(ctx, &d, argv[0])))
        return JS_EXCEPTION;
    return JS_NewBool(ctx, is_safe_integer(d));
}

