static GCValue js_parseInt(JSContextHandle ctx, GCValue this_val,
                           int argc, GCValue *argv)
{
    const char *str, *p;
    int radix, flags;
    GCValue ret;

    str = JS_ToCString(ctx, argv[0]);
    if (!str)
        return JS_EXCEPTION;
    if (JS_ToInt32(ctx, &radix, argv[1])) {
        return JS_EXCEPTION;
    }
    if (radix != 0 && (radix < 2 || radix > 36)) {
        ret = JS_NAN;
    } else {
        p = str;
        p += skip_spaces(p);
        flags = ATOD_INT_ONLY | ATOD_ACCEPT_PREFIX_AFTER_SIGN;
        ret = js_atof(ctx, p, NULL, radix, flags);
    }
    return ret;
}

static GCValue js_parseFloat(JSContextHandle ctx, GCValue this_val,
                             int argc, GCValue *argv)
{
    const char *str, *p;
    GCValue ret;

    str = JS_ToCString(ctx, argv[0]);
    if (!str)
        return JS_EXCEPTION;
    p = str;
    p += skip_spaces(p);
    ret = js_atof(ctx, p, NULL, 10, 0);
    return ret;
}

