/* Promise */

JSPromiseStateEnum JS_PromiseState(JSContextHandle ctx, GCValue promise)
{
    GCHandle s = JS_GetOpaqueHandle(promise, JS_CLASS_PROMISE);
    if (s == GC_HANDLE_NULL)
        return (JSPromiseStateEnum)-1;
    JSPromiseDataHandle ph(s);
    return (JSPromiseStateEnum)ph.promise_state();
}

GCValue JS_PromiseResult(JSContextHandle ctx, GCValue promise)
{
    GCHandle s = JS_GetOpaqueHandle(promise, JS_CLASS_PROMISE);
    if (s == GC_HANDLE_NULL)
        return JS_UNDEFINED;
    JSPromiseDataHandle ph(s);
    return ph.promise_result();
}

