/* AsyncFromSyncIteratorPrototype */

static void js_async_from_sync_iterator_finalizer(JSRuntimeHandle rt, GCValue val)
{
    GCHandle s_handle = JS_GetOpaqueHandle(val, JS_CLASS_ASYNC_FROM_SYNC_ITERATOR);
    if (s_handle == GC_HANDLE_NULL)
        return;
    JSAsyncFromSyncIteratorDataHandle s(s_handle);
    if (s.valid()) {
        
        
        /* GC frees automatically */;
    }
}

static void js_async_from_sync_iterator_mark(JSRuntimeHandle rt, GCValue val,
                                             JS_MarkFunc *mark_func)
{
    GCHandle s_handle = JS_GetOpaqueHandle(val, JS_CLASS_ASYNC_FROM_SYNC_ITERATOR);
    if (s_handle != GC_HANDLE_NULL) {
        /* The async-from-sync-iterator data object is a separate GC allocation; keep it alive. */
        mark_func(rt, s_handle);
        JSAsyncFromSyncIteratorDataHandle s(s_handle);
        JS_MarkValue(rt, s.sync_iter(), mark_func);
        JS_MarkValue(rt, s.next_method(), mark_func);
    }
}

static GCValue JS_CreateAsyncFromSyncIterator(JSContextHandle ctx,
                                              GCValue sync_iter)
{
    GCValue async_iter, next_method;

    next_method = JS_GetProperty(ctx, sync_iter, JS_ATOM_next);
    if (JS_IsException(next_method))
        return JS_EXCEPTION;
    async_iter = JS_NewObjectClass(ctx, JS_CLASS_ASYNC_FROM_SYNC_ITERATOR);
    if (JS_IsException(async_iter)) {
        return async_iter;
    }
    GCHandle s_handle = gc_allocz(sizeof(JSAsyncFromSyncIteratorData), JS_GC_OBJ_TYPE_DATA);
    if (s_handle == GC_HANDLE_NULL) {
        return JS_EXCEPTION;
    }
    JSAsyncFromSyncIteratorDataHandle s(s_handle);
    s.set_sync_iter(sync_iter);
    s.set_next_method(next_method);
    JS_SetOpaqueHandle(async_iter, s_handle);
    return async_iter;
}

static GCValue js_async_from_sync_iterator_unwrap(JSContextHandle ctx,
                                                  GCValue this_val,
                                                  int argc, GCValue *argv,
                                                  int magic, GCValue *func_data)
{
    return js_create_iterator_result(ctx, argv[0],
                                     JS_ToBool(ctx, func_data[0]));
}

static GCValue js_async_from_sync_iterator_unwrap_func_create(JSContextHandle ctx,
                                                              BOOL done)
{
    GCValue func_data[1];

    func_data[0] = (GCValue)JS_NewBool(ctx, done);
    return JS_NewCFunctionData(ctx, js_async_from_sync_iterator_unwrap,
                               1, 0, 1, func_data);
}

static GCValue js_async_from_sync_iterator_close_wrap(JSContextHandle ctx,
                                                      GCValue this_val,
                                                      int argc, GCValue *argv,
                                                      int magic, GCValue *func_data)
{
    JS_Throw(ctx, argv[0]);
    JS_IteratorClose(ctx, func_data[0], TRUE);
    return JS_EXCEPTION;
}

static GCValue js_async_from_sync_iterator_close_wrap_func_create(JSContextHandle ctx, GCValue sync_iter)
{
    return JS_NewCFunctionData(ctx, js_async_from_sync_iterator_close_wrap,
                               1, 0, 1, &sync_iter);
}

static GCValue js_async_from_sync_iterator_next(JSContextHandle ctx, GCValue this_val,
                                                int argc, GCValue *argv,
                                                int magic)
{
    GCValue promise, resolving_funcs[2], value, err, method;
    GCHandle s_handle;
    int done;
    int is_reject;
    GCValue obj;
    GCValue value_wrapper_promise, resolve_reject[2];
    int res;
    GCValue res2;

    promise = JS_NewPromiseCapability(ctx, resolving_funcs);
    if (JS_IsException(promise))
        return JS_EXCEPTION;
    s_handle = JS_GetOpaqueHandle(this_val, JS_CLASS_ASYNC_FROM_SYNC_ITERATOR);
    if (s_handle == GC_HANDLE_NULL)
        return JS_UNDEFINED;
    JSAsyncFromSyncIteratorDataHandle s(s_handle);
    if (!s.valid()) {
        JS_ThrowTypeError(ctx, "not an Async-from-Sync Iterator");
        goto reject;
    }

    if (magic == GEN_MAGIC_NEXT) {
        method = s.next_method();
    } else {
        method = JS_GetProperty(ctx, s.sync_iter(),
                                magic == GEN_MAGIC_RETURN ? JS_ATOM_return :
                                JS_ATOM_throw);
        if (JS_IsException(method))
            goto reject;
        if (JS_IsUndefined(method) || JS_IsNull(method)) {
            if (magic == GEN_MAGIC_RETURN) {
                err = js_create_iterator_result(ctx, argv[0], TRUE);
                is_reject = 0;
                goto done_resolve;
            } else {
                if (JS_IteratorClose(ctx, s.sync_iter(), FALSE))
                    goto reject;
                JS_ThrowTypeError(ctx, "throw is not a method");
                goto reject;
            }
        }
    }
    value = JS_IteratorNext2(ctx, s.sync_iter(), method,
                             argc >= 1 ? 1 : 0, argv, &done);
    
    if (JS_IsException(value))
        goto reject;
    if (done == 2) {
        obj = value;
        value = JS_IteratorGetCompleteValue(ctx, obj, &done);
        
        if (JS_IsException(value))
            goto reject;
    }
    
    if (JS_IsException(value))
        goto reject;
    {
        value_wrapper_promise = js_promise_resolve(ctx, ctx.promise_ctor(),
                                                   1, (GCValue *)&value, 0);
        if (JS_IsException(value_wrapper_promise)) {
            if (magic != GEN_MAGIC_RETURN && !done) {
                JS_IteratorClose(ctx, s.sync_iter(), TRUE);
            }
        reject:
            err = JS_GetException(ctx);
            is_reject = 1;
        done_resolve:
            res2 = JS_Call(ctx, resolving_funcs[is_reject], JS_UNDEFINED,
                           1, (GCValue *)&err);
            
            
            
            
            return promise;
        }

        resolve_reject[0] =
            js_async_from_sync_iterator_unwrap_func_create(ctx, done);
        if (JS_IsException(resolve_reject[0])) {
            
            goto fail;
        }
        if (done || magic == GEN_MAGIC_RETURN) {
            resolve_reject[1] = JS_UNDEFINED;
        } else {
            resolve_reject[1] =
                js_async_from_sync_iterator_close_wrap_func_create(ctx, s.sync_iter());
            if (JS_IsException(resolve_reject[1])) {
                
                
                goto fail;
            }
        }
        
        res = perform_promise_then(ctx, value_wrapper_promise,
                                   (GCValue *)resolve_reject,
                                   (GCValue *)resolving_funcs);
        
        
        
        
        
        if (res) {
            
            return JS_EXCEPTION;
        }
    }
    return promise;
 fail:
    
    
    
    
    return JS_EXCEPTION;
}

