static JSObjectHandle get_typed_array(JSContextHandle ctx, GCValue this_val)
{
    JSObjectHandle p;
    if (JS_VALUE_GET_TAG(this_val) != JS_TAG_OBJECT)
        goto fail;
    p = JS_VALUE_GET_OBJ(this_val);
    if (!(p.class_id() >= JS_CLASS_UINT8C_ARRAY &&
          p.class_id() <= JS_CLASS_FLOAT64_ARRAY)) {
    fail:
        JS_ThrowTypeError(ctx, "not a TypedArray");
        return JSObjectHandle(GC_HANDLE_NULL);
    }
    return p;
}

// is the typed array detached or out of bounds relative to its RAB?
// |p| must be a typed array, *not* a DataView
static BOOL typed_array_is_oob(JSObjectHandle p)
{
    int len, size_elem;
    int64_t end;

    assert(p.class_id() >= JS_CLASS_UINT8C_ARRAY);
    assert(p.class_id() <= JS_CLASS_FLOAT64_ARRAY);

    JSTypedArrayHandle ta = p.typed_array_handle();
    JSObjectHandle abuf_obj(ta.buffer_handle());
    JSArrayBufferHandle abuf = JSArrayBufferHandle(abuf_obj.array_buffer_handle());
    if (abuf.detached())
        return TRUE;
    len = abuf.byte_length();
    if (ta.offset() > len)
        return TRUE;
    if (ta.track_rab())
        return FALSE;
    if (len < (int64_t)ta.offset() + ta.length())
        return TRUE;
    size_elem = 1 << typed_array_size_log2(p.class_id());
    end = (int64_t)ta.offset() + (int64_t)p.array_count() * size_elem;
    return end > len;
}

// Be *very* careful if you touch the typed array's memory directly:
// the length is only valid until the next call into JS land because
// JS code can detach or resize the backing array buffer. Functions
// like JS_GetProperty and JS_ToIndex call JS code.
//
// Exclusively reading or writing elements with JS_GetProperty,
// JS_GetPropertyInt64, JS_SetProperty, etc. is safe because they
// perform bounds checks, as does js_get_fast_array_element.
static int js_typed_array_get_length_unsafe(JSContextHandle ctx, GCValue obj)
{
    JSObjectHandle p;
    p = get_typed_array(ctx, obj);
    if (!p)
        return -1;
    if (typed_array_is_oob(p)) {
        JS_ThrowTypeErrorArrayBufferOOB(ctx);
        return -1;
    }
    return p.array_count();
}

static int validate_typed_array(JSContextHandle ctx, GCValue this_val)
{
    JSObjectHandle p;
    p = get_typed_array(ctx, this_val);
    if (!p)
        return -1;
    if (typed_array_is_oob(p)) {
        JS_ThrowTypeErrorArrayBufferOOB(ctx);
        return -1;
    }
    return 0;
}

static GCValue js_typed_array_get_length(JSContextHandle ctx,
                                         GCValue this_val)
{
    JSObjectHandle p;
    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    return JS_NewInt32(ctx, p.array_count());
}

static GCValue js_typed_array_get_buffer(JSContextHandle ctx,
                                         GCValue this_val)
{
    JSObjectHandle p;
    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    JSTypedArrayHandle ta(p.typed_array_handle());
    return GC_MKHANDLE(JS_TAG_OBJECT, ta.buffer_handle());
}

static GCValue js_typed_array_get_byteLength(JSContextHandle ctx,
                                             GCValue this_val)
{
    JSObjectHandle p;
    int size_log2;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_NewInt32(ctx, 0);
    JSTypedArrayHandle ta(p.typed_array_handle());
    if (!ta.track_rab())
        return JS_NewUint32(ctx, ta.length());
    size_log2 = typed_array_size_log2(p.class_id());
    return JS_NewInt64(ctx, (int64_t)p.array_count() << size_log2);
}

static GCValue js_typed_array_get_byteOffset(JSContextHandle ctx,
                                             GCValue this_val)
{
    JSObjectHandle p;
    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_NewInt32(ctx, 0);
    JSTypedArrayHandle ta(p.typed_array_handle());
    return JS_NewUint32(ctx, ta.offset());
}

GCValue JS_NewTypedArray(JSContextHandle ctx, int argc, GCValue *argv,
                         JSTypedArrayEnum type)
{
    if (type < JS_TYPED_ARRAY_UINT8C || type > JS_TYPED_ARRAY_FLOAT64)
        return JS_ThrowRangeError(ctx, "invalid typed array type");

    return js_typed_array_constructor(ctx, JS_UNDEFINED, argc, argv,
                                      JS_CLASS_UINT8C_ARRAY + type);
}

/* Return the buffer associated to the typed array or an exception if
   it is not a typed array or if the buffer is detached. pbyte_offset,
   pbyte_length or pbytes_per_element can be NULL. */
GCValue JS_GetTypedArrayBuffer(JSContextHandle ctx, GCValue obj,
                               size_t *pbyte_offset,
                               size_t *pbyte_length,
                               size_t *pbytes_per_element)
{
    JSObjectHandle p;
    p = get_typed_array(ctx, obj);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    JSTypedArrayHandle ta(p.typed_array_handle());
    if (pbyte_offset)
        *pbyte_offset = ta.offset();
    if (pbyte_length)
        *pbyte_length = ta.length();
    if (pbytes_per_element) {
        *pbytes_per_element = 1 << typed_array_size_log2(p.class_id());
    }
    return GC_MKHANDLE(JS_TAG_OBJECT, ta.buffer_handle());
}

static GCValue js_typed_array_get_toStringTag(JSContextHandle ctx,
                                              GCValue this_val)
{
    JSObjectHandle p;
    if (JS_VALUE_GET_TAG(this_val) != JS_TAG_OBJECT)
        return JS_UNDEFINED;
    p = JS_VALUE_GET_OBJ(this_val);
    if (!(p.class_id() >= JS_CLASS_UINT8C_ARRAY &&
          p.class_id() <= JS_CLASS_FLOAT64_ARRAY))
        return JS_UNDEFINED;
    JSRuntimeHandle rt = ctx_rt;
    return JS_AtomToString(ctx, ((JSClass*)rt_class_array)[p.class_id()].class_name);
}

static GCValue js_typed_array_set_internal(JSContextHandle ctx,
                                           GCValue dst,
                                           GCValue src,
                                           GCValue off)
{
    JSObjectHandle p;
    JSObjectHandle src_p;
    uint32_t i;
    int64_t dst_len, src_len, offset;
    GCValue val, src_obj = JS_UNDEFINED;

    p = get_typed_array(ctx, dst);
    if (!p)
        goto fail;
    if (JS_ToInt64Sat(ctx, &offset, off))
        goto fail;
    if (offset < 0)
        goto range_error;
    if (typed_array_is_oob(p)) {
    detached:
        JS_ThrowTypeErrorArrayBufferOOB(ctx);
        goto fail;
    }
    dst_len = p.array_count();
    src_obj = JS_ToObject(ctx, src);
    if (JS_IsException(src_obj))
        goto fail;
    src_p = JS_VALUE_GET_OBJ(src_obj);
    if (src_p.class_id() >= JS_CLASS_UINT8C_ARRAY &&
        src_p.class_id() <= JS_CLASS_FLOAT64_ARRAY) {
        JSTypedArrayHandle dest_ta = p.typed_array_handle();
        JSArrayBufferHandle dest_abuf = JSArrayBufferHandle(dest_ta.buffer_handle());
        JSTypedArrayHandle src_ta = src_p.typed_array_handle();
        JSArrayBufferHandle src_abuf = JSArrayBufferHandle(src_ta.buffer_handle());
        int shift = typed_array_size_log2(p.class_id());

        if (typed_array_is_oob(src_p))
            goto detached;

        src_len = src_p.array_count();
        if (offset > dst_len - src_len)
            goto range_error;

        /* copying between typed objects */
        if (src_p.class_id() == p.class_id()) {
            /* same type, use memmove */
            memmove(dest_abuf.data() + dest_ta.offset() + (offset << shift),
                    src_abuf.data() + src_ta.offset(), src_len << shift);
            goto done;
        }
        if (dest_abuf.data() == src_abuf.data()) {
            /* copying between the same buffer using different types of mappings
               would require a temporary buffer */
        }
        /* otherwise, default behavior is slow but correct */
    } else {
        // can change |dst| as a side effect; per spec,
        // perform the range check against its old length
        if (js_get_length64(ctx, &src_len, src_obj))
            goto fail;
        if (offset > dst_len - src_len) {
        range_error:
            JS_ThrowRangeError(ctx, "invalid array length");
            goto fail;
        }
    }
    for(i = 0; i < src_len; i++) {
        val = JS_GetPropertyUint32(ctx, src_obj, i);
        if (JS_IsException(val))
            goto fail;
        if (JS_SetPropertyUint32(ctx, dst, offset + i, val) < 0)
            goto fail;
    }
done:
    
    return JS_UNDEFINED;
fail:
    
    return JS_EXCEPTION;
}

static GCValue js_typed_array_at(JSContextHandle ctx, GCValue this_val,
                                 int argc, GCValue *argv)
{
    JSObjectHandle p;
    int64_t idx, len;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;

    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
    len = p.array_count();

    // note: can change p.array_count()
    if (JS_ToInt64Sat(ctx, &idx, argv[0]))
        return JS_EXCEPTION;

    if (idx < 0)
        idx = len + idx;

    len = p.array_count();
    if (idx < 0 || idx >= len)
        return JS_UNDEFINED;
    return JS_GetPropertyInt64(ctx, this_val, idx);
}

static GCValue js_typed_array_with(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv)
{
    GCValue arr, val;
    JSObjectHandle p;
    int64_t idx, len;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);

    len = p.array_count();
    if (JS_ToInt64Sat(ctx, &idx, argv[0]))
        return JS_EXCEPTION;

    if (idx < 0)
        idx = len + idx;

    val = JS_ToPrimitive(ctx, argv[1], HINT_NUMBER);
    if (JS_IsException(val))
        return JS_EXCEPTION;

    if (typed_array_is_oob(p) || idx < 0 || idx >= p.array_count())
        return JS_ThrowRangeError(ctx, "invalid array index");

    arr = js_typed_array_constructor_ta(ctx, JS_UNDEFINED, this_val,
                                        p.class_id(), len);
    if (JS_IsException(arr)) {
        
        return JS_EXCEPTION;
    }
    if (JS_SetPropertyInt64(ctx, arr, idx, val) < 0) {
        
        return JS_EXCEPTION;
    }
    return arr;
}

static GCValue js_typed_array_set(JSContextHandle ctx,
                                  GCValue this_val,
                                  int argc, GCValue *argv)
{
    GCValue offset = JS_UNDEFINED;
    if (argc > 1) {
        offset = argv[1];
    }
    return js_typed_array_set_internal(ctx, this_val, argv[0], offset);
}

static GCValue js_create_typed_array_iterator(JSContextHandle ctx, GCValue this_val,
                                              int argc, GCValue *argv, int magic)
{
    if (validate_typed_array(ctx, this_val))
        return JS_EXCEPTION;
    return js_create_array_iterator(ctx, this_val, argc, argv, magic);
}

static GCValue js_typed_array_create(JSContextHandle ctx, GCValue ctor,
                                     int argc, GCValue *argv)
{
    GCValue ret;
    int new_len;
    int64_t len;

    ret = JS_CallConstructor(ctx, ctor, argc, argv);
    if (JS_IsException(ret))
        return ret;
    /* validate the typed array */
    new_len = js_typed_array_get_length_unsafe(ctx, ret);
    if (new_len < 0)
        goto fail;
    if (argc == 1) {
        /* ensure that it is large enough */
        if (JS_ToLengthFree(ctx, &len, argv[0]))
            goto fail;
        if (new_len < len) {
            JS_ThrowTypeError(ctx, "TypedArray length is too small");
        fail:
            
            return JS_EXCEPTION;
        }
    }
    return ret;
}

#if 0
static GCValue js_typed_array___create(JSContextHandle ctx,
                                       GCValue this_val,
                                       int argc, GCValue *argv)
{
    return js_typed_array_create(ctx, argv[0], max_int(argc - 1, 0), argv + 1);
}
#endif

static GCValue js_typed_array___speciesCreate(JSContextHandle ctx,
                                              GCValue this_val,
                                              int argc, GCValue *argv)
{
    GCValue obj;
    JSObjectHandle p;
    GCValue ctor, ret;
    int argc1;

    obj = argv[0];
    p = get_typed_array(ctx, obj);
    if (!p)
        return JS_EXCEPTION;
    ctor = JS_SpeciesConstructor(ctx, obj, JS_UNDEFINED);
    if (JS_IsException(ctor))
        return ctor;
    argc1 = max_int(argc - 1, 0);
    if (JS_IsUndefined(ctor)) {
        ret = js_typed_array_constructor(ctx, JS_UNDEFINED, argc1, argv + 1,
                                         p.class_id());
    } else {
        ret = js_typed_array_create(ctx, ctor, argc1, argv + 1);
        
    }
    return ret;
}

static GCValue js_typed_array_from(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv)
{
    // from(items, mapfn = void 0, this_arg = void 0)
    GCValue items = argv[0], mapfn, this_arg;
    GCValue args[2];
    GCValue iter, arr, r, v, v2;
    int64_t k, len;
    int mapping;

    mapping = FALSE;
    mapfn = JS_UNDEFINED;
    this_arg = JS_UNDEFINED;
    r = JS_UNDEFINED;
    arr = JS_UNDEFINED;
    iter = JS_UNDEFINED;

    if (argc > 1) {
        mapfn = argv[1];
        if (!JS_IsUndefined(mapfn)) {
            if (check_function(ctx, mapfn))
                goto exception;
            mapping = 1;
            if (argc > 2)
                this_arg = argv[2];
        }
    }
    iter = JS_GetProperty(ctx, items, JS_ATOM_Symbol_iterator);
    if (JS_IsException(iter))
        goto exception;
    if (!JS_IsUndefined(iter) && !JS_IsNull(iter)) {
        uint32_t len1;
        if (!JS_IsFunction(ctx, iter)) {
            JS_ThrowTypeError(ctx, "value is not iterable");
            goto exception;
        }
        arr = js_array_from_iterator(ctx, &len1, items, iter);
        if (JS_IsException(arr))
            goto exception;
        len = len1;
    } else {
        arr = JS_ToObject(ctx, items);
        if (JS_IsException(arr))
            goto exception;
        if (js_get_length64(ctx, &len, arr) < 0)
            goto exception;
    }
    v = JS_NewInt64(ctx, len);
    args[0] = v;
    r = js_typed_array_create(ctx, this_val, 1, args);
    
    if (JS_IsException(r))
        goto exception;
    for(k = 0; k < len; k++) {
        v = JS_GetPropertyInt64(ctx, arr, k);
        if (JS_IsException(v))
            goto exception;
        if (mapping) {
            args[0] = v;
            args[1] = JS_NewInt32(ctx, k);
            v2 = JS_Call(ctx, mapfn, this_arg, 2, args);
            
            v = v2;
            if (JS_IsException(v))
                goto exception;
        }
        if (JS_SetPropertyInt64(ctx, r, k, v) < 0)
            goto exception;
    }
    goto done;
 exception:
    
    r = JS_EXCEPTION;
 done:
    
    
    return r;
}

static GCValue js_typed_array_of(JSContextHandle ctx, GCValue this_val,
                                 int argc, GCValue *argv)
{
    GCValue obj;
    GCValue args[1];
    int i;

    args[0] = JS_NewInt32(ctx, argc);
    obj = js_typed_array_create(ctx, this_val, 1, args);
    if (JS_IsException(obj))
        return obj;

    for(i = 0; i < argc; i++) {
        if (JS_SetPropertyUint32(ctx, obj, i, argv[i]) < 0) {
            
            return JS_EXCEPTION;
        }
    }
    return obj;
}

static GCValue js_typed_array_copyWithin(JSContextHandle ctx, GCValue this_val,
                                         int argc, GCValue *argv)
{
    JSObjectHandle p;
    int len, to, from, final, count, shift, space;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    len = p.array_count();

    if (JS_ToInt32Clamp(ctx, &to, argv[0], 0, len, len))
        return JS_EXCEPTION;

    if (JS_ToInt32Clamp(ctx, &from, argv[1], 0, len, len))
        return JS_EXCEPTION;

    final = len;
    if (argc > 2 && !JS_IsUndefined(argv[2])) {
        if (JS_ToInt32Clamp(ctx, &final, argv[2], 0, len, len))
            return JS_EXCEPTION;
    }

    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);

    // RAB may have been resized by evil .valueOf method
    space = p.array_count() - max_int(to, from);
    count = min_int(final - from, len - to);
    count = min_int(count, space);
    if (count > 0) {
        shift = typed_array_size_log2(p.class_id());
        memmove(p.array_uint8_ptr() + (to << shift),
                p.array_uint8_ptr() + (from << shift),
                count << shift);
    }
    return this_val;
}

static GCValue js_typed_array_fill(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv)
{
    JSObjectHandle p;
    int len, k, final, shift;
    uint64_t v64;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    len = p.array_count();

    if (p.class_id() == JS_CLASS_UINT8C_ARRAY) {
        int32_t v;
        if (JS_ToUint8ClampFree(ctx, &v, argv[0]))
            return JS_EXCEPTION;
        v64 = v;
    } else if (p.class_id() <= JS_CLASS_UINT32_ARRAY) {
        uint32_t v;
        if (JS_ToUint32(ctx, &v, argv[0]))
            return JS_EXCEPTION;
        v64 = v;
    } else if (p.class_id() <= JS_CLASS_BIG_UINT64_ARRAY) {
        if (JS_ToBigInt64(ctx, (int64_t *)&v64, argv[0]))
            return JS_EXCEPTION;
    } else {
        double d;
        if (JS_ToFloat64(ctx, &d, argv[0]))
            return JS_EXCEPTION;
        if (p.class_id() == JS_CLASS_FLOAT16_ARRAY) {
            v64 = tofp16(d);
        } else if (p.class_id() == JS_CLASS_FLOAT32_ARRAY) {
            union {
                float f;
                uint32_t u32;
            } u;
            u.f = d;
            v64 = u.u32;
        } else {
            JSFloat64Union u;
            u.d = d;
            v64 = u.u64;
        }
    }

    k = 0;
    if (argc > 1) {
        if (JS_ToInt32Clamp(ctx, &k, argv[1], 0, len, len))
            return JS_EXCEPTION;
    }

    final = len;
    if (argc > 2 && !JS_IsUndefined(argv[2])) {
        if (JS_ToInt32Clamp(ctx, &final, argv[2], 0, len, len))
            return JS_EXCEPTION;
    }

    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);

    // RAB may have been resized by evil .valueOf method
    final = min_int(final, p.array_count());
    shift = typed_array_size_log2(p.class_id());
    switch(shift) {
    case 0:
        if (k < final) {
            memset(p.array_uint8_ptr() + k, v64, final - k);
        }
        break;
    case 1:
        for(; k < final; k++) {
            p.array_uint16_ptr()[k] = v64;
        }
        break;
    case 2:
        for(; k < final; k++) {
            p.array_uint32_ptr()[k] = v64;
        }
        break;
    case 3:
        for(; k < final; k++) {
            p.array_uint64_ptr()[k] = v64;
        }
        break;
    default:
        abort();
    }
    return this_val;
}

static GCValue js_typed_array_find(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv, int mode)
{
    GCValue func, this_arg;
    GCValue args[3];
    GCValue val, index_val, res;
    int len, k, end;
    int dir;

    val = JS_UNDEFINED;
    len = js_typed_array_get_length_unsafe(ctx, this_val);
    if (len < 0)
        goto exception;

    func = argv[0];
    if (check_function(ctx, func))
        goto exception;

    this_arg = JS_UNDEFINED;
    if (argc > 1)
        this_arg = argv[1];

    k = 0;
    dir = 1;
    end = len;
    if (mode == ArrayFindLast || mode == ArrayFindLastIndex) {
        k = len - 1;
        dir = -1;
        end = -1;
    }

    for(; k != end; k += dir) {
        index_val = JS_NewInt32(ctx, k);
        val = JS_GetPropertyValue(ctx, this_val, index_val);
        if (JS_IsException(val))
            goto exception;
        args[0] = val;
        args[1] = index_val;
        args[2] = this_val;
        res = JS_Call(ctx, func, this_arg, 3, args);
        if (JS_IsException(res))
            goto exception;
        if (JS_ToBoolFree(ctx, res)) {
            if (mode == ArrayFindIndex || mode == ArrayFindLastIndex) {
                
                return index_val;
            } else {
                return val;
            }
        }
        
    }
    if (mode == ArrayFindIndex || mode == ArrayFindLastIndex)
        return JS_NewInt32(ctx, -1);
    else
        return JS_UNDEFINED;

exception:
    
    return JS_EXCEPTION;
}

#define special_indexOf 0
#define special_lastIndexOf 1
#define special_includes -1

static GCValue js_typed_array_indexOf(JSContextHandle ctx, GCValue this_val,
                                      int argc, GCValue *argv, int special)
{
    JSObjectHandle p;
    int len, tag, is_int, is_bigint, k, stop, inc, res = -1;
    int64_t v64;
    double d;
    float f;
    uint16_t hf;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    len = p.array_count();

    if (len == 0)
        goto done;

    if (special == special_lastIndexOf) {
        k = len - 1;
        if (argc > 1) {
            int64_t k1;
            if (JS_ToInt64Clamp(ctx, &k1, argv[1], -1, len - 1, len))
                goto exception;
            k = k1;
            if (k < 0)
                goto done;
        }
        stop = -1;
        inc = -1;
    } else {
        k = 0;
        if (argc > 1) {
            if (JS_ToInt32Clamp(ctx, &k, argv[1], 0, len, len))
                goto exception;
        }
        stop = len;
        inc = 1;
    }

    /* includes function: 'undefined' can be found if searching out of bounds */
    if (len > p.array_count() && special == special_includes &&
        JS_IsUndefined(argv[0]) && k < len) {
        res = 0;
        goto done;
    }

    // RAB may have been resized by evil .valueOf method
    len = min_int(len, p.array_count());
    if (len == 0)
        goto done;
    if (special == special_lastIndexOf)
        k = min_int(k, len - 1);
    else
        k = min_int(k, len);
    stop = min_int(stop, len);

    is_bigint = 0;
    is_int = 0; /* avoid warning */
    v64 = 0; /* avoid warning */
    tag = JS_VALUE_GET_NORM_TAG(argv[0]);
    if (tag == JS_TAG_INT) {
        is_int = 1;
        v64 = JS_VALUE_GET_INT(argv[0]);
        d = v64;
    } else
    if (tag == JS_TAG_FLOAT64) {
        d = JS_VALUE_GET_FLOAT64(argv[0]);
        if (d >= INT64_MIN && d < 0x1p63) {
            v64 = d;
            is_int = (v64 == d);
        }
    } else if (tag == JS_TAG_BIG_INT || tag == JS_TAG_SHORT_BIG_INT) {
        JSBigIntBuf buf1;
        JSBigInt* p1;
        int sz = (64 / JS_LIMB_BITS);
        if (tag == JS_TAG_SHORT_BIG_INT)
            p1 = js_bigint_set_short(&buf1, argv[0]);
        else {
            JSBigIntHandle bigint1(JS_VALUE_GET_HANDLE(argv[0]));
            p1 = bigint1.unsafe_data();
        }
        
        if (p.class_id() == JS_CLASS_BIG_INT64_ARRAY) {
            if (p1->len > sz)
                goto done; /* does not fit an int64 : cannot be found */
        } else if (p.class_id() == JS_CLASS_BIG_UINT64_ARRAY) {
            if (js_bigint_sign(p1))
                goto done; /* v < 0 */
            if (p1->len <= sz) {
                /* OK */
            } else if (p1->len == sz + 1 && p1->tab[sz] == 0) {
                /* 2^63 <= v <= 2^64-1 */
            } else {
                goto done;
            }
        } else {
            goto done;
        }
        if (JS_ToBigInt64(ctx, &v64, argv[0]))
            goto exception;
        d = 0;
        is_bigint = 1;
    } else {
        goto done;
    }

    switch (p.class_id()) {
    case JS_CLASS_INT8_ARRAY:
        if (is_int && (int8_t)v64 == v64)
            goto scan8;
        break;
    case JS_CLASS_UINT8C_ARRAY:
    case JS_CLASS_UINT8_ARRAY:
        if (is_int && (uint8_t)v64 == v64) {
            const uint8_t *pv, *pp;
            uint16_t v;
        scan8:
            pv = p.array_uint8_ptr();
            v = v64;
            if (inc > 0) {
                pp = NULL;
                if (pv)
                    pp = (const uint8_t *)memchr(pv + k, v, len - k);
                if (pp)
                    res = pp - pv;
            } else {
                for (; k != stop; k += inc) {
                    if (pv[k] == v) {
                        res = k;
                        break;
                    }
                }
            }
        }
        break;
    case JS_CLASS_INT16_ARRAY:
        if (is_int && (int16_t)v64 == v64)
            goto scan16;
        break;
    case JS_CLASS_UINT16_ARRAY:
        if (is_int && (uint16_t)v64 == v64) {
            const uint16_t *pv;
            uint16_t v;
        scan16:
            pv = p.array_uint16_ptr();
            v = v64;
            for (; k != stop; k += inc) {
                if (pv[k] == v) {
                    res = k;
                    break;
                }
            }
        }
        break;
    case JS_CLASS_INT32_ARRAY:
        if (is_int && (int32_t)v64 == v64)
            goto scan32;
        break;
    case JS_CLASS_UINT32_ARRAY:
        if (is_int && (uint32_t)v64 == v64) {
            const uint32_t *pv;
            uint32_t v;
        scan32:
            pv = p.array_uint32_ptr();
            v = v64;
            for (; k != stop; k += inc) {
                if (pv[k] == v) {
                    res = k;
                    break;
                }
            }
        }
        break;
    case JS_CLASS_FLOAT16_ARRAY:
        if (is_bigint)
            break;
        if (isnan(d)) {
            const uint16_t *pv = p.array_fp16_ptr();
            /* special case: indexOf returns -1, includes finds NaN */
            if (special != special_includes)
                goto done;
            for (; k != stop; k += inc) {
                if (isfp16nan(pv[k])) {
                    res = k;
                    break;
                }
            }
        } else if (d == 0) {
            // special case: includes also finds negative zero
            const uint16_t *pv = p.array_fp16_ptr();
            for (; k != stop; k += inc) {
                if (isfp16zero(pv[k])) {
                    res = k;
                    break;
                }
            }
        } else if (hf = tofp16(d), d == fromfp16(hf)) {
            const uint16_t *pv = p.array_fp16_ptr();
            for (; k != stop; k += inc) {
                if (pv[k] == hf) {
                    res = k;
                    break;
                }
            }
        }
        break;
    case JS_CLASS_FLOAT32_ARRAY:
        if (is_bigint)
            break;
        if (isnan(d)) {
            const float *pv = p.array_float_ptr();
            /* special case: indexOf returns -1, includes finds NaN */
            if (special != special_includes)
                goto done;
            for (; k != stop; k += inc) {
                if (isnan(pv[k])) {
                    res = k;
                    break;
                }
            }
        } else if ((f = (float)d) == d) {
            const float *pv = p.array_float_ptr();
            for (; k != stop; k += inc) {
                if (pv[k] == f) {
                    res = k;
                    break;
                }
            }
        }
        break;
    case JS_CLASS_FLOAT64_ARRAY:
        if (is_bigint)
            break;
        if (isnan(d)) {
            const double *pv = p.array_double_ptr();
            /* special case: indexOf returns -1, includes finds NaN */
            if (special != special_includes)
                goto done;
            for (; k != stop; k += inc) {
                if (isnan(pv[k])) {
                    res = k;
                    break;
                }
            }
        } else {
            const double *pv = p.array_double_ptr();
            for (; k != stop; k += inc) {
                if (pv[k] == d) {
                    res = k;
                    break;
                }
            }
        }
        break;
    case JS_CLASS_BIG_INT64_ARRAY:
        if (is_bigint) {
            goto scan64;
        }
        break;
    case JS_CLASS_BIG_UINT64_ARRAY:
        if (is_bigint) {
            const uint64_t *pv;
            uint64_t v;
        scan64:
            pv = p.array_uint64_ptr();
            v = v64;
            for (; k != stop; k += inc) {
                if (pv[k] == v) {
                    res = k;
                    break;
                }
            }
        }
        break;
    }

done:
    if (special == special_includes)
        return JS_NewBool(ctx, res >= 0);
    else
        return JS_NewInt32(ctx, res);

exception:
    return JS_EXCEPTION;
}

static GCValue js_typed_array_join(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv, int toLocaleString)
{
    GCValue sep = JS_UNDEFINED, el;
    StringBuffer b_s, *b = &b_s;
    JSStringHandle s;
    JSObjectHandle p;
    int i, len, oldlen, newlen;
    int c;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    len = oldlen = newlen = p.array_count();

    c = ',';    /* default separator */
    if (!toLocaleString && argc > 0 && !JS_IsUndefined(argv[0])) {
        sep = JS_ToString(ctx, argv[0]);
        if (JS_IsException(sep))
            goto exception;
        s = JS_VALUE_GET_STRING(sep);
        if (s.len() == 1 && !s.is_wide_char())
            c = s.str8()[0];
        else
            c = -1;
        // ToString(sep) can detach or resize the arraybuffer as a side effect
        newlen = p.array_count();
        len = min_int(len, newlen);
    }
    string_buffer_init(ctx, b, 0);

    /* XXX: optimize with direct access */
    for(i = 0; i < len; i++) {
        if (i > 0) {
            if (c >= 0) {
                if (string_buffer_putc8(b, c))
                    goto fail;
            } else {
                if (string_buffer_concat(b, s, 0, s.len()))
                    goto fail;
            }
        }
        el = JS_GetPropertyUint32(ctx, this_val, i);
        /* Can return undefined for example if the typed array is detached */
        if (!JS_IsNull(el) && !JS_IsUndefined(el)) {
            if (JS_IsException(el))
                goto fail;
            if (toLocaleString) {
                el = JS_ToLocaleStringFree(ctx, el);
            }
            if (string_buffer_concat_value_free(b, el))
                goto fail;
        }
    }

    // add extra separators in case RAB was resized by evil .valueOf method
    i = max_int(1, newlen);
    for(/*empty*/; i < oldlen; i++) {
        if (c >= 0) {
            if (string_buffer_putc8(b, c))
                goto fail;
        } else {
            if (string_buffer_concat(b, s, 0, s.len()))
                goto fail;
        }
    }

    
    return string_buffer_end(b);

fail:
    string_buffer_free(b);
    
exception:
    return JS_EXCEPTION;
}

static GCValue js_typed_array_reverse(JSContextHandle ctx, GCValue this_val,
                                      int argc, GCValue *argv)
{
    JSObjectHandle p;
    int len;

    len = js_typed_array_get_length_unsafe(ctx, this_val);
    if (len < 0)
        return JS_EXCEPTION;
    if (len > 0) {
        p = JS_VALUE_GET_OBJ(this_val);
        switch (typed_array_size_log2(p.class_id())) {
        case 0:
            {
                uint8_t *p1 = p.array_uint8_ptr();
                uint8_t *p2 = p1 + len - 1;
                while (p1 < p2) {
                    uint8_t v = *p1;
                    *p1++ = *p2;
                    *p2-- = v;
                }
            }
            break;
        case 1:
            {
                uint16_t *p1 = p.array_uint16_ptr();
                uint16_t *p2 = p1 + len - 1;
                while (p1 < p2) {
                    uint16_t v = *p1;
                    *p1++ = *p2;
                    *p2-- = v;
                }
            }
            break;
        case 2:
            {
                uint32_t *p1 = p.array_uint32_ptr();
                uint32_t *p2 = p1 + len - 1;
                while (p1 < p2) {
                    uint32_t v = *p1;
                    *p1++ = *p2;
                    *p2-- = v;
                }
            }
            break;
        case 3:
            {
                uint64_t *p1 = p.array_uint64_ptr();
                uint64_t *p2 = p1 + len - 1;
                while (p1 < p2) {
                    uint64_t v = *p1;
                    *p1++ = *p2;
                    *p2-- = v;
                }
            }
            break;
        default:
            abort();
        }
    }
    return this_val;
}

static GCValue js_typed_array_toReversed(JSContextHandle ctx, GCValue this_val,
                                         int argc, GCValue *argv)
{
    GCValue arr, ret;
    JSObjectHandle p;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    arr = js_typed_array_constructor_ta(ctx, JS_UNDEFINED, this_val,
                                        p.class_id(), p.array_count());
    if (JS_IsException(arr))
        return JS_EXCEPTION;
    ret = js_typed_array_reverse(ctx, arr, argc, argv);
    
    return ret;
}

static void slice_memcpy(uint8_t *dst, const uint8_t *src, size_t len)
{
    if (dst + len <= src || dst >= src + len) {
        /* no overlap: can use memcpy */
        memcpy(dst, src, len);
    } else {
        /* otherwise the spec mandates byte copy */
        while (len-- != 0)
            *dst++ = *src++;
    }
}

static GCValue js_typed_array_slice(JSContextHandle ctx, GCValue this_val,
                                    int argc, GCValue *argv)
{
    GCValue args[2];
    GCValue arr, val;
    JSObjectHandle p, p1;
    int n, len, start, final, count, shift, space;

    arr = JS_UNDEFINED;
    p = get_typed_array(ctx, this_val);
    if (!p)
        goto exception;
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    len = p.array_count();

    if (JS_ToInt32Clamp(ctx, &start, argv[0], 0, len, len))
        goto exception;
    final = len;
    if (!JS_IsUndefined(argv[1])) {
        if (JS_ToInt32Clamp(ctx, &final, argv[1], 0, len, len))
            goto exception;
    }
    count = max_int(final - start, 0);

    shift = typed_array_size_log2(p.class_id());

    args[0] = this_val;
    args[1] = JS_NewInt32(ctx, count);
    arr = js_typed_array___speciesCreate(ctx, JS_UNDEFINED, 2, args);
    if (JS_IsException(arr))
        goto exception;

    if (count > 0) {
        if (validate_typed_array(ctx, this_val)
        ||  validate_typed_array(ctx, arr))
            goto exception;

        p1 = get_typed_array(ctx, arr);
        space = max_int(0, p.array_count() - start);
        count = min_int(count, space);
        if (p1 && p.class_id() == p1.class_id()) {
            slice_memcpy(p1.array_uint8_ptr(),
                         p.array_uint8_ptr() + (start << shift),
                         count << shift);
        } else {
            for (n = 0; n < count; n++) {
                val = JS_GetPropertyValue(ctx, this_val, JS_NewInt32(ctx, start + n));
                if (JS_IsException(val))
                    goto exception;
                if (JS_SetPropertyValue(ctx, arr, JS_NewInt32(ctx, n), val,
                                        JS_PROP_THROW) < 0)
                    goto exception;
            }
        }
    }
    return arr;

 exception:
    
    return JS_EXCEPTION;
}

static GCValue js_typed_array_subarray(JSContextHandle ctx, GCValue this_val,
                                       int argc, GCValue *argv)
{
    GCValue args[4];
    GCValue arr, ta_buffer;
    JSObjectHandle p;
    int len, start, final, count, shift, offset;
    BOOL is_auto;
    JSTypedArrayHandle ta;
        
    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    len = p.array_count();
    if (JS_ToInt32Clamp(ctx, &start, argv[0], 0, len, len))
        return JS_EXCEPTION;

    shift = typed_array_size_log2(p.class_id());
    ta = JSTypedArrayHandle(p.typed_array_handle());
    /* Read byteOffset (ta->offset) even if detached */
    offset = ta.offset() + (start << shift);

    final = len;
    if (JS_IsUndefined(argv[1])) {
        is_auto = ta.track_rab();
    } else {
        is_auto = FALSE;
        if (JS_ToInt32Clamp(ctx, &final, argv[1], 0, len, len))
            return JS_EXCEPTION;
    } 
    count = max_int(final - start, 0);
    ta_buffer = js_typed_array_get_buffer(ctx, this_val);
    if (JS_IsException(ta_buffer))
        return JS_EXCEPTION;
    args[0] = this_val;
    args[1] = ta_buffer;
    args[2] = JS_NewInt32(ctx, offset);
    args[3] = JS_NewInt32(ctx, count);
    arr = js_typed_array___speciesCreate(ctx, JS_UNDEFINED, is_auto ? 3 : 4, args);
    
    return arr;
}

/* TypedArray.prototype.sort */

static int js_cmp_doubles(double x, double y)
{
    if (isnan(x))    return isnan(y) ? 0 : +1;
    if (isnan(y))    return -1;
    if (x < y)       return -1;
    if (x > y)       return 1;
    if (x != 0)      return 0;
    if (signbit(x))  return signbit(y) ? 0 : -1;
    else             return signbit(y) ? 1 : 0;
}

static int js_TA_cmp_int8(const void *a, const void *b, void *opaque) {
    return *(const int8_t *)a - *(const int8_t *)b;
}

static int js_TA_cmp_uint8(const void *a, const void *b, void *opaque) {
    return *(const uint8_t *)a - *(const uint8_t *)b;
}

static int js_TA_cmp_int16(const void *a, const void *b, void *opaque) {
    return *(const int16_t *)a - *(const int16_t *)b;
}

static int js_TA_cmp_uint16(const void *a, const void *b, void *opaque) {
    return *(const uint16_t *)a - *(const uint16_t *)b;
}

static int js_TA_cmp_int32(const void *a, const void *b, void *opaque) {
    int32_t x = *(const int32_t *)a;
    int32_t y = *(const int32_t *)b;
    return (y < x) - (y > x);
}

static int js_TA_cmp_uint32(const void *a, const void *b, void *opaque) {
    uint32_t x = *(const uint32_t *)a;
    uint32_t y = *(const uint32_t *)b;
    return (y < x) - (y > x);
}

static int js_TA_cmp_int64(const void *a, const void *b, void *opaque) {
    int64_t x = *(const int64_t *)a;
    int64_t y = *(const int64_t *)b;
    return (y < x) - (y > x);
}

static int js_TA_cmp_uint64(const void *a, const void *b, void *opaque) {
    uint64_t x = *(const uint64_t *)a;
    uint64_t y = *(const uint64_t *)b;
    return (y < x) - (y > x);
}

static int js_TA_cmp_float16(const void *a, const void *b, void *opaque) {
    return js_cmp_doubles(fromfp16(*(const uint16_t *)a),
                          fromfp16(*(const uint16_t *)b));
}

static int js_TA_cmp_float32(const void *a, const void *b, void *opaque) {
    return js_cmp_doubles(*(const float *)a, *(const float *)b);
}

static int js_TA_cmp_float64(const void *a, const void *b, void *opaque) {
    return js_cmp_doubles(*(const double *)a, *(const double *)b);
}

static GCValue js_TA_get_int8(JSContextHandle ctx, const void *a) {
    return JS_NewInt32(ctx, *(const int8_t *)a);
}

static GCValue js_TA_get_uint8(JSContextHandle ctx, const void *a) {
    return JS_NewInt32(ctx, *(const uint8_t *)a);
}

static GCValue js_TA_get_int16(JSContextHandle ctx, const void *a) {
    return JS_NewInt32(ctx, *(const int16_t *)a);
}

static GCValue js_TA_get_uint16(JSContextHandle ctx, const void *a) {
    return JS_NewInt32(ctx, *(const uint16_t *)a);
}

static GCValue js_TA_get_int32(JSContextHandle ctx, const void *a) {
    return JS_NewInt32(ctx, *(const int32_t *)a);
}

static GCValue js_TA_get_uint32(JSContextHandle ctx, const void *a) {
    return JS_NewUint32(ctx, *(const uint32_t *)a);
}

static GCValue js_TA_get_int64(JSContextHandle ctx, const void *a) {
    return JS_NewBigInt64(ctx, *(int64_t *)a);
}

static GCValue js_TA_get_uint64(JSContextHandle ctx, const void *a) {
    return JS_NewBigUint64(ctx, *(uint64_t *)a);
}

static GCValue js_TA_get_float16(JSContextHandle ctx, const void *a) {
    return __JS_NewFloat64(ctx, fromfp16(*(const uint16_t *)a));
}

static GCValue js_TA_get_float32(JSContextHandle ctx, const void *a) {
    return __JS_NewFloat64(ctx, *(const float *)a);
}

static GCValue js_TA_get_float64(JSContextHandle ctx, const void *a) {
    return __JS_NewFloat64(ctx, *(const double *)a);
}

struct TA_sort_context {
    JSContextHandle ctx;
    int exception; /* 1 = exception, 2 = detached typed array */
    GCValue arr;
    GCValue cmp;
    GCValue (*getfun)(JSContextHandle ctx, const void *a);
    int elt_size;
};

static int js_TA_cmp_generic(const void *a, const void *b, void *opaque) {
    struct TA_sort_context *psc = (struct TA_sort_context *)opaque;
    JSContextHandle ctx = psc->ctx;
    uint32_t a_idx, b_idx;
    GCValue argv[2];
    GCValue res;
    int cmp;
    JSObjectHandle p;
    
    cmp = 0;
    if (!psc->exception) {
        /* Note: the typed array can be detached without causing an
           error */
        a_idx = *(uint32_t *)a;
        b_idx = *(uint32_t *)b;
        p = JSObjectHandle(GC_VALUE_GET_HANDLE(psc->arr));
        if (a_idx >= p.array_count() || b_idx >= p.array_count()) {
            /* OOB case */
            psc->exception = 2;
            return 0;
        }
        argv[0] = psc->getfun(ctx, p.array_uint8_ptr() +
                              a_idx * (size_t)psc->elt_size);
        argv[1] = psc->getfun(ctx, p.array_uint8_ptr() +
                              b_idx * (size_t)(psc->elt_size));
        res = JS_Call(ctx, psc->cmp, JS_UNDEFINED, 2, argv);
        if (JS_IsException(res)) {
            psc->exception = 1;
            goto done;
        }
        if (JS_VALUE_GET_TAG(res) == JS_TAG_INT) {
            int val = JS_VALUE_GET_INT(res);
            cmp = (val > 0) - (val < 0);
        } else {
            double val;
            if (JS_ToFloat64Free(ctx, &val, res) < 0) {
                psc->exception = 1;
                goto done;
            } else {
                cmp = (val > 0) - (val < 0);
            }
        }
        if (cmp == 0) {
            /* make sort stable: compare array offsets */
            cmp = (a_idx > b_idx) - (a_idx < b_idx);
        }
    done:
        ;
    }
    return cmp;
}

static GCValue js_typed_array_sort(JSContextHandle ctx, GCValue this_val,
                                   int argc, GCValue *argv)
{
    JSObjectHandle p;
    int len;
    size_t elt_size;
    struct TA_sort_context tsc;
    int (*cmpfun)(const void *a, const void *b, void *opaque);
    uint32_t *array_idx;
    void *array_tmp;
    size_t i, j;
    void *array_ptr;

    tsc.ctx = ctx;
    tsc.exception = 0;
    tsc.arr = this_val;
    tsc.cmp = argv[0];

    if (!JS_IsUndefined(tsc.cmp) && check_function(ctx, tsc.cmp))
        return JS_EXCEPTION;
    len = js_typed_array_get_length_unsafe(ctx, this_val);
    if (len < 0)
        return JS_EXCEPTION;

    if (len > 1) {
        p = JS_VALUE_GET_OBJ(this_val);
        switch (p.class_id()) {
        case JS_CLASS_INT8_ARRAY:
            tsc.getfun = js_TA_get_int8;
            cmpfun = js_TA_cmp_int8;
            break;
        case JS_CLASS_UINT8C_ARRAY:
        case JS_CLASS_UINT8_ARRAY:
            tsc.getfun = js_TA_get_uint8;
            cmpfun = js_TA_cmp_uint8;
            break;
        case JS_CLASS_INT16_ARRAY:
            tsc.getfun = js_TA_get_int16;
            cmpfun = js_TA_cmp_int16;
            break;
        case JS_CLASS_UINT16_ARRAY:
            tsc.getfun = js_TA_get_uint16;
            cmpfun = js_TA_cmp_uint16;
            break;
        case JS_CLASS_INT32_ARRAY:
            tsc.getfun = js_TA_get_int32;
            cmpfun = js_TA_cmp_int32;
            break;
        case JS_CLASS_UINT32_ARRAY:
            tsc.getfun = js_TA_get_uint32;
            cmpfun = js_TA_cmp_uint32;
            break;
        case JS_CLASS_BIG_INT64_ARRAY:
            tsc.getfun = js_TA_get_int64;
            cmpfun = js_TA_cmp_int64;
            break;
        case JS_CLASS_BIG_UINT64_ARRAY:
            tsc.getfun = js_TA_get_uint64;
            cmpfun = js_TA_cmp_uint64;
            break;
        case JS_CLASS_FLOAT16_ARRAY:
            tsc.getfun = js_TA_get_float16;
            cmpfun = js_TA_cmp_float16;
            break;
        case JS_CLASS_FLOAT32_ARRAY:
            tsc.getfun = js_TA_get_float32;
            cmpfun = js_TA_cmp_float32;
            break;
        case JS_CLASS_FLOAT64_ARRAY:
            tsc.getfun = js_TA_get_float64;
            cmpfun = js_TA_cmp_float64;
            break;
        default:
            abort();
        }
        elt_size = 1 << typed_array_size_log2(p.class_id());
        if (!JS_IsUndefined(tsc.cmp)) {

            /* XXX: a stable sort would use less memory */
            array_idx = GCPin<uint32_t>(gc_alloc(len * sizeof(array_idx[0]), JS_GC_OBJ_TYPE_DATA)).ptr();
            if (!array_idx)
                return JS_EXCEPTION;
            for(i = 0; i < len; i++)
                array_idx[i] = i;
            tsc.elt_size = elt_size;
            rqsort(array_idx, len, sizeof(array_idx[0]),
                   js_TA_cmp_generic, &tsc);
            if (tsc.exception) {
                if (tsc.exception == 1)
                    return JS_EXCEPTION;
                /* detached typed array during the sort: no error */
            } else {
                array_ptr = p.array_ptr();
                len = min_int(len, p.array_count());
                if (len != 0) {
                    /* Safe: no GC possible between alloc and immediate memcpy use */
                    GCHandle tmp_handle = gc_alloc(len * elt_size, JS_GC_OBJ_TYPE_DATA);
                    if (tmp_handle == GC_HANDLE_NULL) {
                        array_tmp = NULL;
                    } else {
                        /* Safe: immediately after allocation, no GC before use */
                        array_tmp = gc_deref_unsafe(tmp_handle);
                    }
                    if (!array_tmp)
                        return JS_EXCEPTION;
                    memcpy(array_tmp, array_ptr, len * elt_size);
                    switch(elt_size) {
                    case 1:
                        for(i = 0; i < len; i++) {
                            j = array_idx[i];
                            ((uint8_t *)array_ptr)[i] = ((uint8_t *)array_tmp)[j];
                        }
                        break;
                    case 2:
                        for(i = 0; i < len; i++) {
                            j = array_idx[i];
                            ((uint16_t *)array_ptr)[i] = ((uint16_t *)array_tmp)[j];
                        }
                        break;
                    case 4:
                        for(i = 0; i < len; i++) {
                            j = array_idx[i];
                            ((uint32_t *)array_ptr)[i] = ((uint32_t *)array_tmp)[j];
                        }
                        break;
                    case 8:
                        for(i = 0; i < len; i++) {
                            j = array_idx[i];
                            ((uint64_t *)array_ptr)[i] = ((uint64_t *)array_tmp)[j];
                        }
                        break;
                    default:
                        abort();
                    }
                    /* GC frees automatically */;
                }
            }
            /* GC frees automatically */;
        } else {
            rqsort(p.array_ptr(), len, elt_size, cmpfun, &tsc);
            if (tsc.exception)
                return JS_EXCEPTION;
        }
    }
    return this_val;
}

static GCValue js_typed_array_toSorted(JSContextHandle ctx, GCValue this_val,
                                       int argc, GCValue *argv)
{
    GCValue arr, ret;
    JSObjectHandle p;

    p = get_typed_array(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    arr = js_typed_array_constructor_ta(ctx, JS_UNDEFINED, this_val,
                                        p.class_id(), p.array_count());
    if (JS_IsException(arr))
        return JS_EXCEPTION;
    ret = js_typed_array_sort(ctx, arr, argc, argv);
    
    return ret;
}

