static GCValue js_typed_array_base_constructor(JSContextHandle ctx,
                                               GCValue this_val,
                                               int argc, GCValue *argv)
{
    return JS_ThrowTypeError(ctx, "cannot be called");
}

/* 'obj' must be an allocated typed array object */
static int typed_array_init(JSContextHandle ctx, GCValue obj,
                            GCValue buffer, uint64_t offset, uint64_t len,
                            BOOL track_rab)
{
    JSObjectHandle p, pbuffer;
    JSArrayBufferHandle abuf;
    int size_log2;

    p = JS_VALUE_GET_OBJ(obj);
    size_log2 = typed_array_size_log2(p.class_id());
    GCHandle ta_handle = gc_alloc(sizeof(JSTypedArray), JS_GC_OBJ_TYPE_DATA);
    if (ta_handle == GC_HANDLE_NULL) {
        return -1;
    }
    JSTypedArrayHandle ta(ta_handle);
    pbuffer = JSObjectHandle(GC_VALUE_GET_HANDLE(buffer));
    abuf = JSArrayBufferHandle(pbuffer.array_buffer_handle());
    ta.set_obj_handle(p.handle());
    ta.set_buffer_handle(GC_VALUE_GET_HANDLE(buffer));
    ta.set_offset(offset);
    ta.set_length(len << size_log2);
    ta.set_track_rab(track_rab);
    abuf.typed_arrays().push(ta_handle);
    p.set_typed_array_handle(ta_handle);
    p.set_array_count(len);
    p.set_array_ptr(abuf.data() + offset);
    return 0;
}


static GCValue js_array_from_iterator(JSContextHandle ctx, uint32_t *plen,
                                      GCValue obj, GCValue method)
{
    GCValue arr, iter, next_method = JS_UNDEFINED, val;
    BOOL done;
    uint32_t k;

    *plen = 0;
    arr = JS_NewArray(ctx);
    if (JS_IsException(arr))
        return arr;
    iter = JS_GetIterator2(ctx, obj, method);
    if (JS_IsException(iter))
        goto fail;
    next_method = JS_GetProperty(ctx, iter, JS_ATOM_next);
    if (JS_IsException(next_method))
        goto fail;
    k = 0;
    for(;;) {
        val = JS_IteratorNext(ctx, iter, next_method, 0, NULL, &done);
        if (JS_IsException(val))
            goto fail;
        if (done)
            break;
        if (JS_CreateDataPropertyUint32(ctx, arr, k, val, JS_PROP_THROW) < 0)
            goto fail;
        k++;
    }
    
    
    *plen = k;
    return arr;
 fail:
    
    
    
    return JS_EXCEPTION;
}

static GCValue js_typed_array_constructor_obj(JSContextHandle ctx,
                                              GCValue new_target,
                                              GCValue obj,
                                              int classid)
{
    GCValue iter, ret, arr = JS_UNDEFINED, val, buffer;
    uint32_t i;
    int size_log2;
    int64_t len;

    size_log2 = typed_array_size_log2(classid);
    ret = js_create_from_ctor(ctx, new_target, classid);
    if (JS_IsException(ret))
        return JS_EXCEPTION;

    iter = JS_GetProperty(ctx, obj, JS_ATOM_Symbol_iterator);
    if (JS_IsException(iter))
        goto fail;
    if (!JS_IsUndefined(iter) && !JS_IsNull(iter)) {
        uint32_t len1;
        arr = js_array_from_iterator(ctx, &len1, obj, iter);
        
        if (JS_IsException(arr))
            goto fail;
        len = len1;
    } else {
        if (js_get_length64(ctx, &len, obj))
            goto fail;
        arr = obj;
    }

    buffer = js_array_buffer_constructor1(ctx, JS_UNDEFINED,
                                          len << size_log2,
                                          NULL);
    if (JS_IsException(buffer))
        goto fail;
    if (typed_array_init(ctx, ret, buffer, 0, len, /*track_rab*/FALSE))
        goto fail;

    for(i = 0; i < len; i++) {
        val = JS_GetPropertyUint32(ctx, arr, i);
        if (JS_IsException(val))
            goto fail;
        if (JS_SetPropertyUint32(ctx, ret, i, val) < 0)
            goto fail;
    }
    
    return ret;
 fail:
    
    
    return JS_EXCEPTION;
}

static GCValue js_typed_array_constructor_ta(JSContextHandle ctx,
                                             GCValue new_target,
                                             GCValue src_obj,
                                             int classid, uint32_t len)
{
    JSObjectHandle p, src_buffer_obj;
    GCValue obj, buffer;
    uint32_t i;
    int size_log2;
    JSArrayBufferHandle src_abuf;

    obj = js_create_from_ctor(ctx, new_target, classid);
    if (JS_IsException(obj))
        return obj;
    p = JS_VALUE_GET_OBJ(src_obj);
    if (typed_array_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    {
        JSTypedArrayHandle ta_handle = p.typed_array_handle();
        JSObjectHandle src_abuf_obj(ta_handle.buffer_handle());
        src_abuf = JSArrayBufferHandle(src_abuf_obj.array_buffer_handle());
        size_log2 = typed_array_size_log2(classid);
        buffer = js_array_buffer_constructor1(ctx, JS_UNDEFINED,
                                              (uint64_t)len << size_log2,
                                              NULL);
        if (JS_IsException(buffer))
            return JS_EXCEPTION;
        /* necessary because it could have been detached */
        if (typed_array_is_oob(p))
            return JS_ThrowTypeErrorArrayBufferOOB(ctx);
        {
            GCHandle abuf_handle = JS_GetOpaqueHandle(buffer, JS_CLASS_ARRAY_BUFFER);
            if (abuf_handle == GC_HANDLE_NULL)
                return JS_EXCEPTION;
            JSArrayBufferHandle abuf(abuf_handle);
            if (typed_array_init(ctx, obj, buffer, 0, len, /*track_rab*/FALSE))
                return JS_EXCEPTION;
            if (p.class_id() == classid) {
                /* same type: copy the content */
                memcpy(abuf.data(), src_abuf.data() + ta_handle.offset(), abuf.byte_length());
            } else {
                for(i = 0; i < len; i++) {
                    GCValue val;
                    val = JS_GetPropertyUint32(ctx, src_obj, i);
                    if (JS_IsException(val))
                        return JS_EXCEPTION;
                    if (JS_SetPropertyUint32(ctx, obj, i, val) < 0)
                        return JS_EXCEPTION;
                }
            }
        }
    }
    return obj;
}

static GCValue js_typed_array_constructor(JSContextHandle ctx,
                                          GCValue new_target,
                                          int argc, GCValue *argv,
                                          int classid)
{
    BOOL track_rab = FALSE;
    GCValue buffer, obj;
    JSArrayBufferHandle abuf;
    int size_log2;
    uint64_t len, offset;

    size_log2 = typed_array_size_log2(classid);
    if (JS_VALUE_GET_TAG(argv[0]) != JS_TAG_OBJECT) {
        if (JS_ToIndex(ctx, &len, argv[0]))
            return JS_EXCEPTION;
        buffer = js_array_buffer_constructor1(ctx, JS_UNDEFINED,
                                              len << size_log2,
                                              NULL);
        if (JS_IsException(buffer))
            return JS_EXCEPTION;
        offset = 0;
    } else {
        JSObjectHandle p = JS_VALUE_GET_OBJ(argv[0]);
        if (p.class_id() == JS_CLASS_ARRAY_BUFFER ||
            p.class_id() == JS_CLASS_SHARED_ARRAY_BUFFER) {
            abuf = JSArrayBufferHandle(p.array_buffer_handle());
            if (JS_ToIndex(ctx, &offset, argv[1]))
                return JS_EXCEPTION;
            if (abuf.detached())
                return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
            if ((offset & ((1 << size_log2) - 1)) != 0 ||
                offset > abuf.byte_length())
                return JS_ThrowRangeError(ctx, "invalid offset");
            if (JS_IsUndefined(argv[2])) {
                track_rab = abuf.is_resizable();
                if (!track_rab)
                    if ((abuf.byte_length() & ((1 << size_log2) - 1)) != 0)
                        goto invalid_length;
                len = (abuf.byte_length() - offset) >> size_log2;
            } else {
                if (JS_ToIndex(ctx, &len, argv[2]))
                    return JS_EXCEPTION;
                if (abuf.detached())
                    return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
                if ((offset + (len << size_log2)) > abuf.byte_length()) {
                invalid_length:
                    return JS_ThrowRangeError(ctx, "invalid length");
                }
            }
            buffer = argv[0];
        } else {
            if (p.class_id() >= JS_CLASS_UINT8C_ARRAY &&
                p.class_id() <= JS_CLASS_FLOAT64_ARRAY) {
                return js_typed_array_constructor_ta(ctx, new_target, argv[0],
                                                     classid, p.array_count());
            } else {
                return js_typed_array_constructor_obj(ctx, new_target, argv[0], classid);
            }
        }
    }

    obj = js_create_from_ctor(ctx, new_target, classid);
    if (JS_IsException(obj)) {
        
        return JS_EXCEPTION;
    }
    if (typed_array_init(ctx, obj, buffer, offset, len, track_rab)) {
        
        return JS_EXCEPTION;
    }
    return obj;
}

static void js_typed_array_finalizer(JSRuntimeHandle rt, GCValue val)
{
    JSObjectHandle p = JS_VALUE_GET_OBJ(val);
    JSTypedArrayHandle ta = p.typed_array_handle();
    if (ta.valid()) {
        /* Note: typed array is automatically removed from abuf->typed_arrays
           when the array buffer is freed. The GCHandleArray handles this. */
        
        /* GC frees automatically */;
    }
}

static void js_typed_array_mark(JSRuntimeHandle rt, GCValue val,
                                JS_MarkFunc *mark_func)
{
    JSObjectHandle p = JS_VALUE_GET_OBJ(val);
    JSTypedArrayHandle ta = p.typed_array_handle();
    if (ta.valid()) {
        /* Mark the JSTypedArray struct itself to prevent it from being GC'd */
        mark_func(rt, ta.handle());
        GCHandle buf_handle = ta.buffer_handle();
        if (buf_handle != GC_HANDLE_NULL) {
            /* buf_handle is the ArrayBuffer JSObject handle - mark it */
            JS_MarkValue(rt, GC_MKHANDLE(JS_TAG_OBJECT, buf_handle), mark_func);
        }
    }
}

static GCValue js_dataview_constructor(JSContextHandle ctx,
                                       GCValue new_target,
                                       int argc, GCValue *argv)
{
    BOOL recompute_len = FALSE;
    BOOL track_rab = FALSE;
    uint64_t offset;
    uint32_t len;
    GCValue buffer;
    GCValue obj;
    GCHandle ta_handle = GC_HANDLE_NULL;
    JSObjectHandle p;

    buffer = argv[0];
    JSArrayBuffer *abuf_ptr = js_get_array_buffer(ctx, buffer);
    if (!abuf_ptr)
        return JS_EXCEPTION;
    offset = 0;
    if (argc > 1) {
        if (JS_ToIndex(ctx, &offset, argv[1]))
            return JS_EXCEPTION;
    }
    if (abuf_ptr->detached)
        return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
    if (offset > abuf_ptr->byte_length)
        return JS_ThrowRangeError(ctx, "invalid byteOffset");
    len = abuf_ptr->byte_length - offset;
    if (argc > 2 && !JS_IsUndefined(argv[2])) {
        uint64_t l;
        if (JS_ToIndex(ctx, &l, argv[2]))
            return JS_EXCEPTION;
        if (l > len)
            return JS_ThrowRangeError(ctx, "invalid byteLength");
        len = l;
    } else {
        recompute_len = TRUE;
        track_rab = array_buffer_is_resizable(abuf_ptr);
    }

    obj = js_create_from_ctor(ctx, new_target, JS_CLASS_DATAVIEW);
    if (JS_IsException(obj))
        return JS_EXCEPTION;
    if (abuf_ptr->detached)
        return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
    // RAB could have been resized in js_create_from_ctor()
    if (offset > abuf_ptr->byte_length)
        return JS_ThrowRangeError(ctx, "invalid byteOffset or byteLength");
    if (recompute_len)
        len = abuf_ptr->byte_length - offset;
    else if (offset + len > abuf_ptr->byte_length)
        return JS_ThrowRangeError(ctx, "invalid byteOffset or byteLength");

    ta_handle = gc_alloc(sizeof(JSTypedArray), JS_GC_OBJ_TYPE_DATA);
    if (ta_handle == GC_HANDLE_NULL)
        return JS_EXCEPTION;
    {
        JSTypedArrayHandle ta(ta_handle);
        p = JS_VALUE_GET_OBJ(obj);
        ta.set_obj_handle(p.handle());
        ta.set_buffer_handle(GC_VALUE_GET_HANDLE(buffer));
        ta.set_offset(offset);
        ta.set_length(len);
        ta.set_track_rab(track_rab);
        /* WARNING: Using raw pointer - js_create_from_ctor may trigger GC */
        abuf_ptr->typed_arrays.push(ta_handle);
        p.set_typed_array_handle(ta_handle);
    }
    return obj;
}

// is the DataView out of bounds relative to its parent arraybuffer?
static BOOL dataview_is_oob(JSObjectHandle p)
{
    assert(p.class_id() == JS_CLASS_DATAVIEW);
    JSTypedArrayHandle ta = p.typed_array_handle();
    JSObjectHandle abuf_obj(ta.buffer_handle());
    JSArrayBufferHandle abuf = JSArrayBufferHandle(abuf_obj.array_buffer_handle());
    if (abuf.detached())
        return TRUE;
    if (ta.offset() > abuf.byte_length())
        return TRUE;
    if (ta.track_rab())
        return FALSE;
    return (int64_t)ta.offset() + ta.length() > abuf.byte_length();
}

static JSObjectHandle get_dataview(JSContextHandle ctx, GCValue this_val)
{
    JSObjectHandle p;
    if (JS_VALUE_GET_TAG(this_val) != JS_TAG_OBJECT)
        goto fail;
    p = JS_VALUE_GET_OBJ(this_val);
    if (p.class_id() != JS_CLASS_DATAVIEW) {
    fail:
        JS_ThrowTypeError(ctx, "not a DataView");
        return JSObjectHandle(GC_HANDLE_NULL);
    }
    return p;
}

static GCValue js_dataview_get_buffer(JSContextHandle ctx, GCValue this_val)
{
    JSObjectHandle p;
    p = get_dataview(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    JSTypedArrayHandle ta(p.typed_array_handle());
    return GC_MKHANDLE(JS_TAG_OBJECT, ta.buffer_handle());
}

static GCValue js_dataview_get_byteLength(JSContextHandle ctx, GCValue this_val)
{
    JSObjectHandle p;

    p = get_dataview(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (dataview_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    JSTypedArrayHandle ta = p.typed_array_handle();
    if (ta.track_rab()) {
        JSObjectHandle abuf_obj(ta.buffer_handle());
        JSArrayBufferHandle abuf = JSArrayBufferHandle(abuf_obj.array_buffer_handle());
        return JS_NewUint32(ctx, abuf.byte_length() - ta.offset());
    }
    return JS_NewUint32(ctx, ta.length());
}

static GCValue js_dataview_get_byteOffset(JSContextHandle ctx, GCValue this_val)
{
    JSObjectHandle p;

    p = get_dataview(ctx, this_val);
    if (!p)
        return JS_EXCEPTION;
    if (dataview_is_oob(p))
        return JS_ThrowTypeErrorArrayBufferOOB(ctx);
    JSTypedArrayHandle ta = p.typed_array_handle();
    return JS_NewUint32(ctx, ta.offset());
}

static GCValue js_dataview_getValue(JSContextHandle ctx,
                                    GCValue this_obj,
                                    int argc, GCValue *argv, int class_id)
{
    BOOL littleEndian, is_swap;
    int size;
    uint8_t *ptr;
    uint32_t v;
    uint64_t pos;

    GCHandle ta_handle = JS_GetOpaqueHandle2(ctx, this_obj, JS_CLASS_DATAVIEW);
    if (ta_handle == GC_HANDLE_NULL)
        return JS_EXCEPTION;
    JSTypedArrayHandle ta(ta_handle);
    size = 1 << typed_array_size_log2(class_id);
    if (JS_ToIndex(ctx, &pos, argv[0]))
        return JS_EXCEPTION;
    littleEndian = argc > 1 && JS_ToBool(ctx, argv[1]);
    is_swap = littleEndian ^ !is_be();
    JSObjectHandle abuf_obj(ta.buffer_handle());
    JSArrayBufferHandle abuf = JSArrayBufferHandle(abuf_obj.array_buffer_handle());
    if (abuf.detached()) {
        fprintf(stderr, "[DATAVIEW] detached error: ta=%u buf_handle=%u abuf=%u detached=%d data=%p byte_len=%d\n",
                ta.handle(), ta.buffer_handle(), abuf.handle(), abuf.detached(), abuf.data(), abuf.byte_length());
        return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
    }
    // order matters: this check should come before the next one
    if ((pos + size) > ta.length())
        return JS_ThrowRangeError(ctx, "out of bound");
    // test262 expects a TypeError for this and V8, in its infinite wisdom,
    // throws a "detached array buffer" exception, but IMO that doesn't make
    // sense because the buffer is not in fact detached, it's still there
    if ((int64_t)ta.offset() + ta.length() > abuf.byte_length())
        return JS_ThrowTypeError(ctx, "out of bound");
    ptr = abuf.data() + ta.offset() + pos;

    switch(class_id) {
    case JS_CLASS_INT8_ARRAY:
        return JS_NewInt32(ctx, *(int8_t *)ptr);
    case JS_CLASS_UINT8_ARRAY:
        return JS_NewInt32(ctx, *(uint8_t *)ptr);
    case JS_CLASS_INT16_ARRAY:
        v = get_u16(ptr);
        if (is_swap)
            v = bswap16(v);
        return JS_NewInt32(ctx, (int16_t)v);
    case JS_CLASS_UINT16_ARRAY:
        v = get_u16(ptr);
        if (is_swap)
            v = bswap16(v);
        return JS_NewInt32(ctx, v);
    case JS_CLASS_INT32_ARRAY:
        v = get_u32(ptr);
        if (is_swap)
            v = bswap32(v);
        return JS_NewInt32(ctx, v);
    case JS_CLASS_UINT32_ARRAY:
        v = get_u32(ptr);
        if (is_swap)
            v = bswap32(v);
        return JS_NewUint32(ctx, v);
    case JS_CLASS_BIG_INT64_ARRAY:
        {
            uint64_t v;
            v = get_u64(ptr);
            if (is_swap)
                v = bswap64(v);
            return JS_NewBigInt64(ctx, v);
        }
        break;
    case JS_CLASS_BIG_UINT64_ARRAY:
        {
            uint64_t v;
            v = get_u64(ptr);
            if (is_swap)
                v = bswap64(v);
            return JS_NewBigUint64(ctx, v);
        }
        break;
    case JS_CLASS_FLOAT16_ARRAY:
        {
            uint16_t v;
            v = get_u16(ptr);
            if (is_swap)
                v = bswap16(v);
            return __JS_NewFloat64(ctx, fromfp16(v));
        }
    case JS_CLASS_FLOAT32_ARRAY:
        {
            union {
                float f;
                uint32_t i;
            } u;
            v = get_u32(ptr);
            if (is_swap)
                v = bswap32(v);
            u.i = v;
            return __JS_NewFloat64(ctx, u.f);
        }
    case JS_CLASS_FLOAT64_ARRAY:
        {
            union {
                double f;
                uint64_t i;
            } u;
            u.i = get_u64(ptr);
            if (is_swap)
                u.i = bswap64(u.i);
            return __JS_NewFloat64(ctx, u.f);
        }
    default:
        abort();
    }
}

static GCValue js_dataview_setValue(JSContextHandle ctx,
                                    GCValue this_obj,
                                    int argc, GCValue *argv, int class_id)
{
    BOOL littleEndian, is_swap;
    int size;
    uint8_t *ptr;
    uint64_t v64;
    uint32_t v;
    uint64_t pos;
    GCValue val;

    GCHandle ta_handle = JS_GetOpaqueHandle2(ctx, this_obj, JS_CLASS_DATAVIEW);
    if (ta_handle == GC_HANDLE_NULL)
        return JS_EXCEPTION;
    JSTypedArrayHandle ta(ta_handle);
    size = 1 << typed_array_size_log2(class_id);
    if (JS_ToIndex(ctx, &pos, argv[0]))
        return JS_EXCEPTION;
    val = argv[1];
    v = 0; /* avoid warning */
    v64 = 0; /* avoid warning */
    if (class_id <= JS_CLASS_UINT32_ARRAY) {
        if (JS_ToUint32(ctx, &v, val))
            return JS_EXCEPTION;
    } else if (class_id <= JS_CLASS_BIG_UINT64_ARRAY) {
        if (JS_ToBigInt64(ctx, (int64_t *)&v64, val))
            return JS_EXCEPTION;
    } else {
        double d;
        if (JS_ToFloat64(ctx, &d, val))
            return JS_EXCEPTION;
        if (class_id == JS_CLASS_FLOAT16_ARRAY) {
            v = tofp16(d);
        } else if (class_id == JS_CLASS_FLOAT32_ARRAY) {
            union {
                float f;
                uint32_t i;
            } u;
            u.f = d;
            v = u.i;
        } else {
            JSFloat64Union u;
            u.d = d;
            v64 = u.u64;
        }
    }
    littleEndian = argc > 2 && JS_ToBool(ctx, argv[2]);
    is_swap = littleEndian ^ !is_be();
    JSObjectHandle abuf_obj(ta.buffer_handle());
    JSArrayBufferHandle abuf = JSArrayBufferHandle(abuf_obj.array_buffer_handle());
    if (abuf.detached()) {
        fprintf(stderr, "[SETVALUE] detached error: ta=%u buf_handle=%u abuf=%u detached=%d data=%p byte_len=%d\n",
                ta.handle(), ta.buffer_handle(), abuf.handle(), abuf.detached(), abuf.data(), abuf.byte_length());
        return JS_ThrowTypeErrorDetachedArrayBuffer(ctx);
    }
    // order matters: this check should come before the next one
    if ((pos + size) > ta.length()) {
        fprintf(stderr, "[SETVALUE] out of bound: pos=%llu size=%d ta_len=%u ta_offset=%u abuf_len=%d\n",
                (unsigned long long)pos, size, ta.length(), ta.offset(), abuf.byte_length());
        return JS_ThrowRangeError(ctx, "out of bound");
    }
    // test262 expects a TypeError for this and V8, in its infinite wisdom,
    // throws a "detached array buffer" exception, but IMO that doesn't make
    // sense because the buffer is not in fact detached, it's still there
    if ((int64_t)ta.offset() + ta.length() > abuf.byte_length())
        return JS_ThrowTypeError(ctx, "out of bound");
    ptr = abuf.data() + ta.offset() + pos;

    switch(class_id) {
    case JS_CLASS_INT8_ARRAY:
    case JS_CLASS_UINT8_ARRAY:
        *ptr = v;
        break;
    case JS_CLASS_INT16_ARRAY:
    case JS_CLASS_UINT16_ARRAY:
    case JS_CLASS_FLOAT16_ARRAY:
        if (is_swap)
            v = bswap16(v);
        put_u16(ptr, v);
        break;
    case JS_CLASS_INT32_ARRAY:
    case JS_CLASS_UINT32_ARRAY:
    case JS_CLASS_FLOAT32_ARRAY:
        if (is_swap)
            v = bswap32(v);
        put_u32(ptr, v);
        break;
    case JS_CLASS_BIG_INT64_ARRAY:
    case JS_CLASS_BIG_UINT64_ARRAY:
    case JS_CLASS_FLOAT64_ARRAY:
        if (is_swap)
            v64 = bswap64(v64);
        put_u64(ptr, v64);
        break;
    default:
        abort();
    }
    return JS_UNDEFINED;
}

