#include "quickjs_handle_classes.h"


/* ============================================================================
 * UNIFIED GC BRIDGE FUNCTIONS
 * 
 * These functions provide an interface between the unified GC in 
 * quickjs_gc_unified.cpp and the QuickJS engine. They allow the unified GC
 * to access QuickJS internals for comprehensive marking and sweeping.
 * ============================================================================ */

/* Runtime getter functions */
extern "C" uint32_t JSRuntime_get_permanent_atom_count(JSRuntimeHandle rt) {
    return rt.permanent_atom_count();
}

extern "C" uint32_t JSRuntime_get_atom_hash_size(JSRuntimeHandle rt) {
    LFHashTable *t = rt.atom_hash();
    return t ? t->bucket_count : 0;
}

extern "C" uint32_t JSRuntime_get_atom_hash_count(JSRuntimeHandle rt) {
    return rt.atom_hash_count();
}

extern "C" uint32_t *JSRuntime_get_atom_hash(JSRuntimeHandle rt) {
    return NULL;
}

extern "C" uint32_t JSRuntime_get_shape_hash_size(JSRuntimeHandle rt) {
    return rt.shape_hash_size();
}

extern "C" uint32_t JSRuntime_get_shape_hash_count(JSRuntimeHandle rt) {
    return rt.shape_hash_count();
}

extern "C" void JSRuntime_set_shape_hash_count(JSRuntimeHandle rt, uint32_t count) {
    rt.set_shape_hash_count(count);
}

extern "C" uint32_t *JSRuntime_get_shape_hash(JSRuntimeHandle rt) {
    return NULL;
}

extern "C" int JSShape_is_hashed(uint32_t shape_handle) {
    if (shape_handle == GC_HANDLE_NULL) return 0;
    JSShapeHandle sh(shape_handle);
    return sh.is_hashed() ? 1 : 0;
}

extern "C" void JSShape_set_is_hashed(uint32_t shape_handle, int val) {
    if (shape_handle == GC_HANDLE_NULL) return;
    JSShapeHandle sh(shape_handle);
    sh.set_is_hashed(val ? TRUE : FALSE);
}

extern "C" uint32_t JSString_get_hash_next(uint32_t atom_idx) {
    /* Get the hash_next field from an atom string */
    /* This requires accessing the atom_array, which is runtime-specific */
    /* For now, return 0 as this is handled differently in the actual sweep */
    return 0;
}

extern "C" void JSString_set_hash_next(uint32_t atom_idx, uint32_t next) {
    /* Set the hash_next field - handled differently in actual sweep */
    (void)atom_idx;
    (void)next;
}

/* Job queue access - returns GCHandle to job entry */
extern "C" uint32_t JSRuntime_job_queue_count(JSRuntimeHandle rt) {
    return rt.job_queue().count();
}

extern "C" uint32_t JSRuntime_job_queue_get_handle(JSRuntimeHandle rt, int index) {
    GCHandleRingBuffer& job_queue = rt.job_queue();
    if (index < 0 || index >= job_queue.count()) return GC_HANDLE_NULL;
    GCHandle job_handle = job_queue[index];
    if (!gc_handle_array_entry_is_valid(job_handle)) return GC_HANDLE_NULL;
    return job_handle;
}

/* Access job entry fields directly via handle */
extern "C" uint32_t JSJobEntry_get_realm_handle(uint32_t job_handle) {
    if (job_handle == GC_HANDLE_NULL) return GC_HANDLE_NULL;
    JSJobEntryHandle jh(job_handle);
    if (!jh) return GC_HANDLE_NULL;
    return jh.realm_handle();
}

extern "C" int JSJobEntry_get_argc(uint32_t job_handle) {
    if (job_handle == GC_HANDLE_NULL) return 0;
    JSJobEntryHandle jh(job_handle);
    if (!jh) return 0;
    return jh.argc();
}

extern "C" GCValue JSJobEntry_get_argv(uint32_t job_handle, int index) {
    GCValue result;
    result.tag = JS_TAG_UNDEFINED;
    result.u.handle = GC_HANDLE_NULL;
    if (job_handle == GC_HANDLE_NULL) return result;
    JSJobEntryHandle jh(job_handle);
    if (!jh) return result;
    if (index >= 0 && index < jh.argc()) {
        return jh.argv_at(index);
    }
    return result;
}

/* Handle array getters */
extern "C" uint32_t JSRuntime_get_shape_hash_handle(JSRuntimeHandle rt) {
    return GC_HANDLE_NULL;
}

extern "C" uint32_t JSRuntime_get_atom_array_handle(JSRuntimeHandle rt) {
    return rt.atom_array_handle();
}

extern "C" GCValue JSRuntime_get_current_exception(JSRuntimeHandle rt) {
    return rt.current_exception();
}

/* Stack frame access */
extern "C" JSStackFrame *JSRuntime_get_current_stack_frame(JSRuntimeHandle rt) {
    return rt.current_stack_frame();
}

extern "C" GCValue JSStackFrame_get_cur_func(JSStackFrame *sf) {
    GCValue result;
    result.tag = JS_TAG_UNDEFINED;
    result.u.handle = GC_HANDLE_NULL;
    if (!sf) return result;
    return sf->cur_func;
}

extern "C" JSStackFrame *JSStackFrame_get_prev(JSStackFrame *sf) {
    if (!sf) return NULL;
    return JS_SF_PREV(sf);
}

/* Context iteration callback type */
typedef void (*ContextIteratorFunc)(uint32_t ctx_handle, void *user_data);

static void js_runtime_context_iterator_callback(GCHandle handle, void *user_data) {
    struct { ContextIteratorFunc func; void *user_data; JSRuntimeHandle rt; } *cb = 
        (decltype(cb))user_data;
    cb->func(handle, cb->user_data);
}

extern "C" void JSRuntime_for_each_context(JSRuntimeHandle rt, ContextIteratorFunc func, void *user_data) {
    struct { ContextIteratorFunc func; void *user_data; JSRuntimeHandle rt; } cb = {func, user_data, rt};
    gc_for_each_object_of_type(JS_GC_OBJ_TYPE_JS_CONTEXT, js_runtime_context_iterator_callback, &cb);
}

